def clean_MCB():
    import numpy as np
    import torch
    import torch.nn as nn
    import torch.optim as optim
    from torch.utils.data import DataLoader, TensorDataset
    from sklearn.preprocessing import RobustScaler, StandardScaler
    from sklearn.model_selection import train_test_split
    from sklearn.metrics import mean_squared_error, mean_absolute_error, r2_score
    import matplotlib.pyplot as plt
    import pickle
    import os
    import random
    import pandas as pd
    import json  # 添加json用于保存索引

    # 设置随机种子
    random.seed(42)
    np.random.seed(42)
    torch.manual_seed(42)
    if torch.cuda.is_available():
        torch.cuda.manual_seed_all(42)

    # 确保 cuDNN 确定性
    torch.backends.cudnn.deterministic = True
    torch.backends.cudnn.benchmark = False

    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    print(f"Using device: {device}")

    # ==========================
    # 1. Load Data
    # ==========================
    print("\n" + "=" * 60)
    print("STEP 1: Loading Data")
    print("=" * 60)

    # 读取数据（跳过第一行的列名）
    data = np.loadtxt('./LHSOutputs_995percent_PARSEC_new20000lhs_withMCB.dat', skiprows=1)
    print(f"Original data shape: {data.shape}")

    # 定义列名称（用于DataFrame）
    column_names = [
        'N_ait', 'R_ait', 'GSD_ait',
        'N_acc', 'R_acc', 'GSD_acc',
        'N_coa', 'R_coa', 'GSD_coa',
        'N_mcb', 'R_mcb', 'GSD_mcb',
        'temperature', 'pressure', 'updraft',
        'ait_maf', 'acc_maf', 'coa_maf', 'mcb_maf',
        'Nact', 'Smax', 'runtime_seconds'
    ]

    # 创建DataFrame便于操作
    df = pd.DataFrame(data, columns=column_names)
    print(f"DataFrame shape: {df.shape}")

    # ==========================
    # 2. Data Cleaning
    # ==========================
    print("\n" + "=" * 60)
    print("STEP 2: Data Cleaning")
    print("=" * 60)

    # 记录原始数据量
    original_count = len(df)
    print(f"Original number of runs: {original_count}")

    # 2.1 检查NaN值
    print("\n2.1 Checking for NaN values...")
    nan_mask = df['Smax'].isna() | df['runtime_seconds'].isna()
    nan_count = nan_mask.sum()
    print(f"  Rows with NaN in Smax or runtime_seconds: {nan_count}")

    # 2.2 清洗条件1: runtime_seconds > 250
    print("\n2.2 Filtering out runs with runtime_seconds > 250...")
    runtime_mask = df['runtime_seconds'] > 250
    runtime_count = runtime_mask.sum()
    print(f"  Rows with runtime_seconds > 250: {runtime_count}")
    print(f"  Runtime range: [{df['runtime_seconds'].min():.2f}, {df['runtime_seconds'].max():.2f}]")

    # 2.3 清洗条件2: Smax < 0
    print("\n2.3 Filtering out runs with Smax < 0...")
    smax_mask = df['Smax'] < 0
    smax_count = smax_mask.sum()
    print(f"  Rows with Smax < 0: {smax_count}")
    print(f"  Smax range: [{df['Smax'].min():.2f}, {df['Smax'].max():.2f}]")

    # 应用所有清洗条件
    clean_mask = ~(nan_mask | runtime_mask | smax_mask)
    kept_df = df[clean_mask].copy()  # 保留的样本（用于训练）
    removed_df = df[~clean_mask].copy()  # 清洗掉的样本（保存到单独文件）

    # ==========================
    # 2.4 获取并保存unclean samples的索引数组
    # ==========================
    print("\n" + "=" * 60)
    print("STEP 2.4: Saving Unclean Samples Indices")
    print("=" * 60)

    # 获取unclean samples的索引（原始DataFrame中的索引）
    unclean_indices = df[~clean_mask].index.tolist()
    unclean_indices_array = np.array(unclean_indices)

    print(f"Number of unclean samples: {len(unclean_indices_array)}")
    print(f"Unclean indices range: [{unclean_indices_array.min()}, {unclean_indices_array.max()}]")
    print(f"First 10 unclean indices (if available): {unclean_indices_array[:10]}")


    # 同时保存为.txt文件（可读的文本格式）
    indices_txt_file = './unclean_samples_indices.txt'
    with open(indices_txt_file, 'w') as f:
        f.write(f"# Unclean samples indices\n")
        f.write(f"# Total count: {len(unclean_indices_array)}\n")
        f.write(f"# Created from data cleaning process\n")
        f.write(f"# Conditions: NaN values, runtime_seconds > 250, Smax < 0\n\n")
        f.write("Indices:\n")
        for idx in unclean_indices_array:
            f.write(f"{idx}\n")
    print(f"Unclean indices saved to (text format): {indices_txt_file}")


    kept_count = len(kept_df)
    removed_count = len(removed_df)

    print("\n" + "-" * 40)
    print(f"CLEANING SUMMARY:")
    print(f"  Original runs: {original_count}")
    print(f"  Removed runs (unclean): {removed_count} ({removed_count / original_count * 100:.2f}%)")
    print(f"  Kept runs (clean for training): {kept_count} ({kept_count / original_count * 100:.2f}%)")
    print("-" * 40)

    # 显示清洗后数据的统计信息
    print("\nKept data (for training) statistics:")
    print(f"  runtime_seconds range: [{kept_df['runtime_seconds'].min():.2f}, {kept_df['runtime_seconds'].max():.2f}]")
    print(f"  Smax range: [{kept_df['Smax'].min():.2f}, {kept_df['Smax'].max():.2f}]")
    print(f"  Nact range: [{kept_df['Nact'].min():.2e}, {kept_df['Nact'].max():.2e}]")

    print("\nRemoved data (unclean) statistics:")
    if removed_count > 0:
        print(
            f"  runtime_seconds range: [{removed_df['runtime_seconds'].min():.2f}, {removed_df['runtime_seconds'].max():.2f}]")
        print(f"  Smax range: [{removed_df['Smax'].min():.2f}, {removed_df['Smax'].max():.2f}]")
    else:
        print("  No removed data")

    # ==========================
    # 3. Save datasets to CSV files
    # ==========================
    print("\n" + "=" * 60)
    print("STEP 3: Saving Datasets to CSV")
    print("=" * 60)

    # 带单位的列名用于CSV输出
    csv_column_names_with_units = [
        'N_ait [m^-3]', 'R_ait [m]', 'GSD_ait [unitless]',
        'N_acc [m^-3]', 'R_acc [m]', 'GSD_acc [unitless]',
        'N_coa [m^-3]', 'R_coa [m]', 'GSD_coa [unitless]',
        'N_mcb [m^-3]', 'R_mcb [m]', 'GSD_mcb [unitless]',
        'temperature [K]', 'pressure [Pa]', 'updraft [m s^-1]',
        'ait_maf [unitless]', 'acc_maf [unitless]', 'coa_maf [unitless]',
        'mcb_maf [unitless]', 'Nact [m^-3]', 'Smax [%%]', 'runtime_seconds [s]'
    ]

    # 3.1 保存清洗掉的样本（unclean data）
    if removed_count > 0:
        removed_df_with_units = removed_df.copy()
        removed_df_with_units.columns = csv_column_names_with_units
        removed_csv_file = './LHSOutputs_UNCLEAN_samples.csv'
        removed_df_with_units.to_csv(removed_csv_file, index=False)
        print(f"Unclean samples saved to: {removed_csv_file}")
        print(f"  Shape: {removed_df_with_units.shape}")
    else:
        print("No unclean samples to save")

    # 3.2 保存保留的样本（clean data for training）
    kept_df_with_units = kept_df.copy()
    kept_df_with_units.columns = csv_column_names_with_units
    kept_csv_file = './LHSOutputs_CLEAN_for_training.csv'
    kept_df_with_units.to_csv(kept_csv_file, index=False)
    print(f"\nClean samples (for training) saved to: {kept_csv_file}")
    print(f"  Shape: {kept_df_with_units.shape}")

    # 显示前几行预览
    print("\nPreview of clean data (first 5 rows):")
    print(kept_df_with_units.head())

    # ==========================
    # 4. 验证保存的索引文件
    # ==========================
    print("\n" + "=" * 60)
    print("STEP 4: Verifying Saved Indices")
    print("=" * 60)

    # 加载并验证.npy文件
    loaded_indices = np.load(indices_npy_file)
    print(f"Loaded indices from .npy file: {len(loaded_indices)} indices")
    print(f"Match with original? {np.array_equal(loaded_indices, unclean_indices_array)}")

    # 显示统计信息
    print(f"\nIndex statistics:")
    print(f"  Total unclean samples: {len(unclean_indices_array)}")
    print(f"  Min index: {unclean_indices_array.min()}")
    print(f"  Max index: {unclean_indices_array.max()}")
    print(f"  Mean index: {unclean_indices_array.mean():.2f}")
    print(f"  Std index: {unclean_indices_array.std():.2f}")

    print("\nAll index files saved successfully!")







def select_best_one_MCB():

    import numpy as np
    import pandas as pd
    import matplotlib.pyplot as plt
    import xarray as xr
    import os
    import glob
    import time
    from typing import Dict, List, Tuple, Any, Callable
    from dataclasses import dataclass
    from sklearn.preprocessing import RobustScaler, StandardScaler
    from sklearn.model_selection import train_test_split
    from sklearn.metrics import mean_squared_error, r2_score, mean_absolute_error
    import torch
    import torch.nn as nn
    import gpytorch
    import torch.optim as optim
    from torch.utils.data import DataLoader, TensorDataset
    from sklearn.gaussian_process import GaussianProcessRegressor
    from sklearn.gaussian_process.kernels import RBF, Matern, WhiteKernel, RationalQuadratic, ConstantKernel
    from sklearn.decomposition import PCA
    from scipy.special import softmax
    from sklearn.metrics import mean_squared_error, mean_absolute_error, r2_score
    import seaborn as sns
    from scipy import stats
    from matplotlib.gridspec import GridSpec
    import warnings

    warnings.filterwarnings('ignore')

    # ============================================================================
    # 1. 配置类 - 集中管理所有参数
    # ============================================================================
    @dataclass
    class Config:
        """全局配置参数"""
        # 随机种子
        seed: int = 42

        # 数据参数 - 修改为清洗后的数据文件
        data_file: str = 'LHSOutputs_995percent_new20000lhs_clean_only_runagain.csv'  # 改为清洗后的CSV文件
        # data_file: str = 'LHSOutputs_995percent_PARSEC_new20000lhs_withMCB.dat'  # 原文件

        # 修改列索引：新数据有19个输入特征（包括所有GSD），不再是15个
        cols_to_keep: List[int] = None  # 将在__post_init__中初始化
        target_col: int = 19  # Nact是第20列（索引19），保持不变

        # 修改对数变换的列索引（相对于新的cols_to_keep）
        log_transform_cols: List[int] = None  # 将在__post_init__中初始化

        # 训练参数
        train_sizes: List[int] = None  # 不同训练样本量
        n_repeats: int = 1  # 每个样本量的重复次数
        test_ratio: float = 0.0  # 测试集比例
        val_ratio: float = 0.2  # 验证集比例（从训练集中分出）

        # OAT参数
        oat_dir: str = './'
        oat_file_pattern: str = 'LHSOutputs_PARSEC_*.dat'
        background_nc_file: str = './NEP.nc'

        # 输出参数
        output_figure: str = 'OAT_sensitivity_comparison.png'

        def __post_init__(self):
            if self.cols_to_keep is None:
                # 原始列索引：0-21共22列
                # 需要保留的列：去掉索引2,5,8 (GSD列) 和索引18 (mcb_maf)
                #
                # 原始列对应关系：
                # 0:N_ait, 1:R_ait, 2:GSD_ait(去掉), 3:N_acc, 4:R_acc, 5:GSD_acc(去掉),
                # 6:N_coa, 7:R_coa, 8:GSD_coa(去掉), 9:N_mcb, 10:R_mcb, 11:GSD_mcb,
                # 12:temperature, 13:pressure, 14:updraft, 15:ait_maf, 16:acc_maf,
                # 17:coa_maf, 18:mcb_maf(去掉), 19:Nact, 20:Smax, 21:runtime_seconds

                # 保留的列索引
                self.cols_to_keep = [0, 1, 3, 4, 6, 7, 9, 10, 11, 12, 13, 14, 15, 16, 17]

                # 说明：共15个输入特征
                # 包含：N_ait, R_ait, N_acc, R_acc, N_coa, R_coa, N_mcb, R_mcb, GSD_mcb,
                #       temperature, pressure, updraft, ait_maf, acc_maf, coa_maf

            if self.log_transform_cols is None:
                # 需要log变换的特征索引（相对于新的cols_to_keep）
                # 新cols_to_keep中，N_ait在索引0, N_acc在索引2, N_coa在索引4, N_mcb在索引6
                self.log_transform_cols = [0, 2, 4, 6]

            if self.train_sizes is None:
                self.train_sizes = [100]

    # ============================================================================
    # 2. 数据预处理
    # ============================================================================
    class DataPreprocessor:
        """统一的数据预处理接口"""

        def __init__(self, log_cols: List[int], feature_names: List[str] = None):
            self.log_cols = log_cols
            self.feature_names = feature_names  # 保存特征名称
            self.scaler_X = None
            self.scaler_y = None

        def fit_transform(self, X: np.ndarray, y: np.ndarray) -> Tuple[np.ndarray, np.ndarray]:
            """拟合并转换数据"""
            # 处理缺失值
            X = np.nan_to_num(X)
            y = np.nan_to_num(y)

            # 检查负值（对于log变换）
            for col in self.log_cols:
                if col < X.shape[1]:
                    min_val = X[:, col].min()
                    if min_val < 0:
                        print(f"  Warning: Column {col} has negative values ({min_val:.2e}), clipping to 0")
                        X[:, col] = np.maximum(X[:, col], 0)

            # 对数变换
            X_transformed = X.copy()
            for col in self.log_cols:
                if col < X.shape[1]:
                    X_transformed[:, col] = np.log1p(X_transformed[:, col])
                    print(f"  Applied log1p to column {col}")

            y_log = np.log1p(y)
            print(f"  Applied log1p to target")

            # 标准化
            self.scaler_X = RobustScaler()
            X_scaled = self.scaler_X.fit_transform(X_transformed)
            print(f"  X scaled with RobustScaler")

            self.scaler_y = StandardScaler()
            y_scaled = self.scaler_y.fit_transform(y_log.reshape(-1, 1)).flatten()
            print(f"  y scaled with StandardScaler")

            return X_scaled, y_scaled

        def transform(self, X: np.ndarray) -> np.ndarray:
            """仅转换（用于测试集）"""
            X = np.nan_to_num(X)
            X_transformed = X.copy()
            for col in self.log_cols:
                if col < X.shape[1]:
                    X_transformed[:, col] = np.log1p(np.maximum(X_transformed[:, col], 0))
            return self.scaler_X.transform(X_transformed)

        def transform_y(self, y: np.ndarray) -> np.ndarray:
            """转换目标变量（仅标准化，不进行log变换）"""
            y = np.nan_to_num(y)
            y_log = np.log1p(y)
            return self.scaler_y.transform(y_log.reshape(-1, 1)).flatten()

        def inverse_transform_y(self, y_scaled: np.ndarray) -> np.ndarray:
            """逆转换目标变量"""
            y_log = self.scaler_y.inverse_transform(y_scaled.reshape(-1, 1)).flatten()
            return np.expm1(y_log)

    # ============================================================================
    # 3. 模型基类 - 所有模型必须继承此类
    # ============================================================================
    class BaseModel:
        """模型基类，定义统一接口"""

        def __init__(self, **kwargs):
            self.config = kwargs
            self.preprocessor = None
            self.training_time = 0

        def train(self, X: np.ndarray, y: np.ndarray, X_val: np.ndarray = None, y_val: np.ndarray = None):
            """
            训练模型
            Args:
                X, y: 训练数据
                X_val, y_val: 验证数据（可选，用于早停）
            """
            raise NotImplementedError

        def predict(self, X: np.ndarray) -> np.ndarray:
            """预测"""
            raise NotImplementedError

        def get_name(self) -> str:
            """返回模型名称"""
            return self.__class__.__name__



    # ============================================================================
    # 4. 具体模型实现示例
    # ============================================================================

    #===============================================
    class AdaptiveResidualNet(nn.Module):
        """自适应残差网络：根据输入特征动态调整残差强度"""

        def __init__(self, input_dim=15):
            super().__init__()

            # 主网络
            self.fc1 = nn.Linear(input_dim, 128)
            self.norm1 = nn.LayerNorm(128)
            self.fc2 = nn.Linear(128, 256)
            self.norm2 = nn.LayerNorm(256)
            self.fc3 = nn.Linear(256, 128)
            self.norm3 = nn.LayerNorm(128)
            self.fc4 = nn.Linear(128, 1)

            self.act = nn.SiLU()
            self.dropout = nn.Dropout(0.1)

            # 残差适配层
            self.res_adapt = nn.Linear(input_dim, 128)

            # 门控网络：动态决定残差强度
            self.gate = nn.Sequential(
                nn.Linear(input_dim, 32),
                nn.SiLU(),
                nn.Linear(32, 1),
                nn.Sigmoid()
            )

        def forward(self, x):
            # 计算残差
            identity = self.res_adapt(x)

            # 动态门控（基于输入）
            gate_value = self.gate(x)  # [batch, 1]

            # 主路径
            out = self.act(self.norm1(self.fc1(x)))
            out = self.dropout(out)
            out = self.fc2(out)
            out = self.norm2(out)
            out = self.act(out)
            out = self.dropout(out)
            out = self.fc3(out)
            out = self.norm3(out)

            # 自适应残差连接：门控控制残差强度
            out = self.act(out + gate_value * identity)

            out = self.fc4(out)
            return out.squeeze()

    class AdaptiveHuber(nn.Module):
        """自适应 Huber 损失：动态调整 delta 参数"""

        def __init__(self, initial_delta=0.05, min_delta=0.001, decay_rate=8.0):
            super().__init__()
            self.initial_delta = initial_delta
            self.min_delta = min_delta
            self.decay_rate = decay_rate
            self.current_delta = initial_delta

        def update_delta(self, epoch, total_epochs):
            progress = epoch / total_epochs
            self.current_delta = self.min_delta + (self.initial_delta - self.min_delta) * np.exp(
                -self.decay_rate * progress)

        def forward(self, pred, target):
            error = pred - target
            abs_error = torch.abs(error)
            delta = self.current_delta
            quadratic = torch.minimum(abs_error, torch.tensor(delta).to(error.device))
            linear = abs_error - quadratic
            return (0.5 * quadratic ** 2 + delta * linear).mean()

    class EnhancedDNNModel(BaseModel):
        """增强版 DNN 模型类（继承 BaseModel）"""

        def __init__(self, input_dim=15, n_epochs=300, learning_rate=3e-4,
                     weight_decay=1e-2, batch_size=16, patience=20, **kwargs):
            super().__init__(**kwargs)
            self.input_dim = input_dim
            self.n_epochs = n_epochs
            self.learning_rate = learning_rate
            self.weight_decay = weight_decay
            self.batch_size = batch_size
            self.patience = patience
            self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")

            self.model = None
            self.train_losses = []
            self.val_losses = []
            self.learning_rates = []  # 添加学习率记录
            self.epoch_times = []  # 添加训练时间记录
            self.training_time = 0  # 添加训练时间属性

        def train(self, X, y, X_val=None, y_val=None):
            start_time = time.time()

            # 重置历史记录
            self.train_losses = []
            self.val_losses = []
            self.learning_rates = []
            self.epoch_times = []

            # 转换为 tensor
            X_tensor = torch.tensor(X, dtype=torch.float32).to(self.device)
            y_tensor = torch.tensor(y, dtype=torch.float32).to(self.device)

            # 创建数据加载器
            train_dataset = TensorDataset(X_tensor, y_tensor)
            # 设置数据加载器的随机种子
            g = torch.Generator()
            g.manual_seed(42)  # 固定种子

            train_loader = DataLoader(
                train_dataset,
                batch_size=self.batch_size,
                shuffle=True,
                generator=g  # 使用固定种子的生成器
            )

            # 准备验证集
            has_val = X_val is not None and y_val is not None
            if has_val:
                X_val_tensor = torch.tensor(X_val, dtype=torch.float32).to(self.device)
                y_val_tensor = torch.tensor(y_val, dtype=torch.float32).to(self.device)

            # 初始化模型
            self.model = AdaptiveResidualNet(input_dim=self.input_dim).to(self.device)

            # 损失函数
            criterion = AdaptiveHuber(initial_delta=0.05, min_delta=0.001, decay_rate=8)

            # 优化器
            optimizer = optim.AdamW(self.model.parameters(),
                                    lr=self.learning_rate,
                                    weight_decay=self.weight_decay)

            # 学习率调度器
            scheduler = optim.lr_scheduler.CosineAnnealingWarmRestarts(optimizer, T_0=50, T_mult=2)

            # 训练循环
            best_loss = float('inf')
            counter = 0
            best_state = None

            print(f"    开始训练 Enhanced DNN ({self.n_epochs} epochs)...")

            for epoch in range(self.n_epochs):
                epoch_start = time.time()  # 记录epoch开始时间
                # 更新自适应 Huber 的 delta
                criterion.update_delta(epoch, self.n_epochs)

                # 训练阶段
                self.model.train()
                total_loss = 0
                for xb, yb in train_loader:
                    optimizer.zero_grad()
                    pred = self.model(xb)
                    loss = criterion(pred, yb)
                    loss.backward()
                    torch.nn.utils.clip_grad_norm_(self.model.parameters(), 1.0)
                    optimizer.step()
                    total_loss += loss.item()

                avg_train_loss = total_loss / len(train_loader)
                self.train_losses.append(avg_train_loss)

                # 记录学习率
                current_lr = optimizer.param_groups[0]['lr']
                self.learning_rates.append(current_lr)

                # 学习率更新
                scheduler.step()

                # 验证阶段
                self.model.eval()
                with torch.no_grad():
                    if has_val:
                        val_pred = self.model(X_val_tensor)
                        val_loss = criterion(val_pred, y_val_tensor).item()
                    else:
                        val_pred = self.model(X_tensor)
                        val_loss = criterion(val_pred, y_tensor).item()

                self.val_losses.append(val_loss)

                # 记录epoch时间
                self.epoch_times.append(time.time() - epoch_start)

                # 早停检查
                if val_loss < best_loss:
                    best_loss = val_loss
                    best_state = {k: v.cpu().clone() for k, v in self.model.state_dict().items()}
                    counter = 0
                else:
                    counter += 1

                if counter > self.patience:
                    print(f"      早停于 epoch {epoch} (patience={self.patience})")
                    break

                if (epoch + 1) % 50 == 0 or epoch == 0:
                    print(
                        f"      Epoch {epoch + 1}/{self.n_epochs}: Train Loss = {avg_train_loss:.4f}, "
                        f"Val Loss = {val_loss:.4f}, LR = {current_lr:.6f}"
                    )

            # 加载最佳模型
            if best_state is not None:
                self.model.load_state_dict(best_state)

            self.training_time = time.time() - start_time
            print(f"    训练完成，最佳验证损失: {best_loss:.4f}, 训练时间: {self.training_time:.2f}s")

            return {
                'train_losses': self.train_losses,
                'val_losses': self.val_losses,
                'learning_rates': self.learning_rates,
                'epoch_times': self.epoch_times,
                'best_loss': best_loss
            }

        def train_with_history(self, X, y, X_val=None, y_val=None):
            """训练并返回历史记录（兼容接口）"""
            result = self.train(X, y, X_val, y_val)
            return {'model': self.model, 'history': result}

        def predict(self, X):
            X_tensor = torch.tensor(X, dtype=torch.float32).to(self.device)
            self.model.eval()
            with torch.no_grad():
                pred = self.model(X_tensor).cpu().numpy()
            return pred

        def get_name(self):
            return "EnhancedDNN"
    #===============================================













    # ============================================================================
    # 5. 训练和评估管理器
    # ============================================================================
    class ModelTrainer:
        """负责模型的训练和评估"""

        def __init__(self, config: Config):
            self.config = config
            np.random.seed(config.seed)
            torch.manual_seed(config.seed)
            self.plotter = Plotter()  # 添加绘图器

            # 创建模型保存目录
            self.model_save_dir = './saved_models/'
            os.makedirs(self.model_save_dir, exist_ok=True)

        def save_model(self, model: BaseModel, model_name: str, n_samples: int, repeat: int, metrics: Dict):
            """保存训练好的模型（只保存权重，不保存完整对象）"""
            # 创建模型专属目录
            model_dir = os.path.join(self.model_save_dir, model_name)
            os.makedirs(model_dir, exist_ok=True)

            # 生成文件名
            timestamp = time.strftime("%Y%m%d_%H%M%S")
            file_prefix = f"{model_name}_N{n_samples}_rep{repeat}_{timestamp}"

            # 只保存模型权重（不保存完整对象）
            if hasattr(model, 'model') and model.model is not None:
                model_path = os.path.join(model_dir, f"{file_prefix}_weights.pth")
                torch.save({
                    'model_state_dict': model.model.state_dict(),
                    'model_config': {
                        'input_dim': model.input_dim,
                        'n_epochs': model.n_epochs,
                        'learning_rate': model.learning_rate,
                        'weight_decay': model.weight_decay,
                        'batch_size': model.batch_size,
                        'patience': model.patience
                    },
                    'metrics': metrics,
                    'n_samples': n_samples,
                    'repeat': repeat,
                    'timestamp': timestamp
                }, model_path)
                print(f"      模型权重已保存: {model_path}")

            # 保存预处理器
            if hasattr(model, 'preprocessor') and model.preprocessor is not None:
                scaler_path = os.path.join(model_dir, f"{file_prefix}_preprocessor.pkl")
                with open(scaler_path, 'wb') as f:
                    pickle.dump({
                        'scaler_X': model.preprocessor.scaler_X,
                        'scaler_y': model.preprocessor.scaler_y,
                        'log_cols': model.preprocessor.log_cols,
                        'feature_names': model.preprocessor.feature_names
                    }, f)
                print(f"      预处理器已保存: {scaler_path}")

            # 保存训练历史
            if hasattr(model, 'train_losses') and model.train_losses:
                history_path = os.path.join(model_dir, f"{file_prefix}_training_history.npz")
                np.savez(history_path,
                         train_losses=model.train_losses,
                         val_losses=model.val_losses,
                         learning_rates=model.learning_rates if hasattr(model, 'learning_rates') else [],
                         epoch_times=model.epoch_times if hasattr(model, 'epoch_times') else [])
                print(f"      训练历史已保存: {history_path}")

            # 保存性能指标 - 修改这里
            metrics_path = os.path.join(model_dir, f"{file_prefix}_metrics.txt")
            with open(metrics_path, 'w') as f:
                f.write(f"Model: {model_name}\n")
                f.write(f"Training samples: {n_samples}\n")
                f.write(f"Repeat: {repeat}\n")
                f.write(f"Timestamp: {timestamp}\n")
                f.write(f"\nPerformance Metrics:\n")
                f.write(f"{'=' * 40}\n")

                # 修改：直接遍历 metrics 字典的键值对
                for dataset, dataset_metrics in metrics.items():
                    if dataset == 'training_time':  # 跳过 training_time
                        continue
                    f.write(f"\n{dataset.upper()} SET:\n")
                    # dataset_metrics 已经是字典，直接遍历
                    for metric_name, metric_value in dataset_metrics.items():
                        f.write(f"  {metric_name}: {metric_value:.6f}\n")

                # 单独写入训练时间
                if 'training_time' in metrics:
                    f.write(f"\nTraining time: {metrics['training_time']:.2f} seconds\n")

            print(f"      性能指标已保存: {metrics_path}")

        def prepare_data(self, X_full: np.ndarray, y_full: np.ndarray,
                         n_samples: int, repeat: int) -> Dict[str, np.ndarray]:
            """
            划分数据：训练集、验证集
            使用80%训练，20%验证
            """
            total_samples = len(X_full)

            # 确保n_samples不超过总样本数
            n_samples = min(n_samples, total_samples)
            print(f"    Using {n_samples} samples out of {total_samples} total")

            # 如果n_samples小于总样本数，先采样
            if n_samples < total_samples:
                indices = np.random.RandomState(self.config.seed + repeat).permutation(total_samples)[:n_samples]
                X_subset = X_full[indices]
                y_subset = y_full[indices]
            else:
                X_subset = X_full
                y_subset = y_full

            # 80%训练，20%验证
            X_train, X_val, y_train, y_val = train_test_split(
                X_subset, y_subset,
                test_size=self.config.val_ratio,  # 0.2
                random_state=self.config.seed + repeat,
                shuffle=True
            )

            print(f"    Training samples: {len(X_train)}")
            print(f"    Validation samples: {len(X_val)}")

            return {
                'train': (X_train, y_train),
                'val': (X_val, y_val),
                'test': (None, None)  # 没有测试集
            }

        # ========== 添加这个方法 ==========
        def train_and_evaluate(self, model: BaseModel, X_full: np.ndarray,
                               y_full: np.ndarray, n_samples: int, repeat: int) -> Dict:
            """
            训练单个模型并返回评估结果（增强版）
            """
            # 1. 划分数据
            data_split = self.prepare_data(X_full, y_full, n_samples, repeat)
            X_train, y_train = data_split['train']
            X_val, y_val = data_split['val']

            # 2. 预处理
            preprocessor = DataPreprocessor(self.config.log_transform_cols)
            X_train_scaled, y_train_scaled = preprocessor.fit_transform(X_train, y_train)
            X_val_scaled = preprocessor.transform(X_val)
            y_val_scaled = preprocessor.transform_y(y_val)

            # 3. 训练（记录训练历史）
            model.preprocessor = preprocessor

            # 检查模型是否有 train_with_history 方法
            if hasattr(model, 'train_with_history'):
                result = model.train_with_history(X_train_scaled, y_train_scaled,
                                                  X_val_scaled, y_val_scaled)
                training_history = result.get('history', {})
            else:
                model.train(X_train_scaled, y_train_scaled, X_val_scaled, y_val_scaled)
                training_history = {}

            # 4. 评估
            y_train_pred_scaled = model.predict(X_train_scaled)
            y_val_pred_scaled = model.predict(X_val_scaled)

            # 逆变换
            y_train_pred = preprocessor.inverse_transform_y(y_train_pred_scaled)
            y_val_pred = preprocessor.inverse_transform_y(y_val_pred_scaled)

            # 计算指标
            metrics = {
                'train': self._calculate_metrics(y_train, y_train_pred),
                'val': self._calculate_metrics(y_val, y_val_pred),
                'training_time': model.training_time
            }

            # 5. 保存模型（新增）
            model_name = model.get_name()
            self.save_model(model, model_name, n_samples, repeat, metrics)

            # 5. 生成可视化（可选）
            if n_samples == max(self.config.train_sizes) :#and repeat == 0:
                # 只为最大的训练集和第一次重复生成可视化
                model_name = model.get_name()
                save_dir = f'./visualizations/{model_name}/'
                os.makedirs(save_dir, exist_ok=True)

                # 绘制预测分析图
                self.plotter.plot_prediction_analysis(
                    y_val, y_val_pred,
                    title=f'{model_name} - Validation Set Predictions (N={n_samples})',
                    save_path=os.path.join(save_dir, f'validation_predictions_N{n_samples}.png')
                )

                # 绘制训练历史
                if training_history:
                    self.plotter.plot_training_history(
                        training_history,
                        save_path=os.path.join(save_dir, f'training_history_N{n_samples}.png')
                    )

            return {
                'model': model,
                'metrics': metrics,
                'data_split': data_split,
                'training_history': training_history,
                'y_val_true': y_val,
                'y_val_pred': y_val_pred
            }

        # ========== 添加这个方法 ==========
        def _calculate_metrics(self, y_true: np.ndarray, y_pred: np.ndarray) -> Dict:
            """计算评估指标"""
            return {
                'RMSE': np.sqrt(mean_squared_error(y_true, y_pred)),
                'MAE': mean_absolute_error(y_true, y_pred),
                'R2': r2_score(y_true, y_pred)
            }


    class Plotter:
        """增强的可视化类"""

        def __init__(self, style='seaborn-v0_8-darkgrid'):
            """初始化绘图设置"""
            plt.style.use(style)
            self.colors = plt.cm.Set1(np.linspace(0, 1, 10))

        def plot_training_history(self, history: Dict, save_path: str = 'training_history.png'):
            """
            绘制训练历史（损失曲线、学习率等）

            Args:
                history: 包含训练过程的字典
                save_path: 保存路径
            """
            fig, axes = plt.subplots(2, 2, figsize=(14, 10))

            # 1. 损失曲线
            ax1 = axes[0, 0]
            if 'train_losses' in history:
                ax1.plot(history['train_losses'], label='Train Loss', color='blue', alpha=0.7)
            if 'val_losses' in history:
                ax1.plot(history['val_losses'], label='Validation Loss', color='red', alpha=0.7)
            ax1.set_xlabel('Epoch', fontsize=12)
            ax1.set_ylabel('Loss', fontsize=12)
            ax1.set_title('Training and Validation Loss', fontsize=14, fontweight='bold')
            ax1.legend()
            ax1.grid(True, alpha=0.3)

            # 2. 学习率变化
            ax2 = axes[0, 1]
            if 'learning_rates' in history:
                ax2.plot(history['learning_rates'], color='green', alpha=0.7)
                ax2.set_xlabel('Epoch', fontsize=12)
                ax2.set_ylabel('Learning Rate', fontsize=12)
                ax2.set_title('Learning Rate Schedule', fontsize=14, fontweight='bold')
                ax2.set_yscale('log')
                ax2.grid(True, alpha=0.3)

            # 3. 指标变化
            ax3 = axes[1, 0]
            if 'metrics_history' in history:
                metrics_df = pd.DataFrame(history['metrics_history'])
                for col in metrics_df.columns:
                    ax3.plot(metrics_df[col], label=col, alpha=0.7)
                ax3.set_xlabel('Epoch', fontsize=12)
                ax3.set_ylabel('Metric Value', fontsize=12)
                ax3.set_title('Metrics Evolution', fontsize=14, fontweight='bold')
                ax3.legend()
                ax3.grid(True, alpha=0.3)

            # 4. 梯度范数
            ax4 = axes[1, 1]
            if 'gradient_norms' in history:
                ax4.plot(history['gradient_norms'], color='purple', alpha=0.7)
                ax4.set_xlabel('Epoch', fontsize=12)
                ax4.set_ylabel('Gradient Norm', fontsize=12)
                ax4.set_title('Gradient Norms', fontsize=14, fontweight='bold')
                ax4.set_yscale('log')
                ax4.grid(True, alpha=0.3)

            plt.tight_layout()
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            plt.show()
            print(f"Training history plot saved to {save_path}")

        def plot_prediction_analysis(self, y_true: np.ndarray, y_pred: np.ndarray,
                                     title: str = 'Prediction Analysis',
                                     save_path: str = None):
            """
            详细的预测分析图

            Args:
                y_true: 真实值
                y_pred: 预测值
                title: 图标题
                save_path: 保存路径
            """
            fig = plt.figure(figsize=(16, 12))
            gs = GridSpec(3, 3, figure=fig, hspace=0.3, wspace=0.3)

            # 计算残差
            residuals = y_true - y_pred
            residuals_rel = residuals / (y_true + 1e-8) * 100  # 相对残差(%)

            # 1. 散点图 (实际 vs 预测)
            ax1 = fig.add_subplot(gs[0, :2])
            ax1.scatter(y_true, y_pred, alpha=0.5, c='blue', s=20)

            # 添加完美预测线
            min_val = min(y_true.min(), y_pred.min())
            max_val = max(y_true.max(), y_pred.max())
            ax1.plot([min_val, max_val], [min_val, max_val], 'r--', alpha=0.8, label='Perfect Prediction')

            # 添加±20%误差带
            ax1.fill_between([min_val, max_val],
                             [min_val * 0.8, max_val * 0.8],
                             [min_val * 1.2, max_val * 1.2],
                             alpha=0.2, color='gray', label='±20% Error Band')

            ax1.set_xlabel('True Values', fontsize=12)
            ax1.set_ylabel('Predicted Values', fontsize=12)
            ax1.set_title(f'{title} - Scatter Plot', fontsize=14, fontweight='bold')
            ax1.legend()
            ax1.grid(True, alpha=0.3)

            # 2. 残差分布
            ax2 = fig.add_subplot(gs[0, 2])
            ax2.hist(residuals, bins=50, edgecolor='black', alpha=0.7, color='steelblue')
            ax2.axvline(x=0, color='red', linestyle='--', linewidth=2)
            ax2.set_xlabel('Residuals', fontsize=12)
            ax2.set_ylabel('Frequency', fontsize=12)
            ax2.set_title('Residual Distribution', fontsize=12, fontweight='bold')
            ax2.grid(True, alpha=0.3, axis='y')

            # 添加统计信息
            textstr = f'Mean: {residuals.mean():.3e}\nStd: {residuals.std():.3e}'
            ax2.text(0.95, 0.95, textstr, transform=ax2.transAxes,
                     fontsize=10, verticalalignment='top', horizontalalignment='right',
                     bbox=dict(boxstyle='round', facecolor='wheat', alpha=0.5))

            # 3. 残差 vs 预测值
            ax3 = fig.add_subplot(gs[1, :2])
            ax3.scatter(y_pred, residuals, alpha=0.5, c='green', s=20)
            ax3.axhline(y=0, color='red', linestyle='--', linewidth=2)
            ax3.set_xlabel('Predicted Values', fontsize=12)
            ax3.set_ylabel('Residuals', fontsize=12)
            ax3.set_title('Residuals vs Predicted Values', fontsize=12, fontweight='bold')
            ax3.grid(True, alpha=0.3)

            # 添加平滑线
            if len(y_pred) > 10:
                from scipy.ndimage import gaussian_filter1d
                order = np.argsort(y_pred)
                smooth_residuals = gaussian_filter1d(residuals[order], sigma=2)
                ax3.plot(y_pred[order], smooth_residuals, 'r-', linewidth=2, label='Trend')
                ax3.legend()

            # 4. Q-Q图
            ax4 = fig.add_subplot(gs[1, 2])
            stats.probplot(residuals, dist="norm", plot=ax4)
            ax4.set_title('Q-Q Plot of Residuals', fontsize=12, fontweight='bold')
            ax4.grid(True, alpha=0.3)

            # 5. 相对误差分布
            ax5 = fig.add_subplot(gs[2, 0])
            ax5.hist(residuals_rel, bins=50, edgecolor='black', alpha=0.7, color='coral')
            ax5.axvline(x=0, color='red', linestyle='--', linewidth=2)
            ax5.set_xlabel('Relative Error (%)', fontsize=12)
            ax5.set_ylabel('Frequency', fontsize=12)
            ax5.set_title('Relative Error Distribution', fontsize=12, fontweight='bold')
            ax5.grid(True, alpha=0.3, axis='y')

            # 6. 误差箱线图（分位数）
            ax6 = fig.add_subplot(gs[2, 1])
            percentiles = np.percentile(y_true, [0, 25, 50, 75, 100])
            error_by_bin = []
            bin_labels = []
            for i in range(len(percentiles) - 1):
                mask = (y_true >= percentiles[i]) & (y_true <= percentiles[i + 1])
                if mask.sum() > 0:
                    error_by_bin.append(residuals_rel[mask])
                    bin_labels.append(f'[{percentiles[i]:.1e},\n{percentiles[i + 1]:.1e}]')

            bp = ax6.boxplot(error_by_bin, labels=bin_labels, patch_artist=True)
            for patch, color in zip(bp['boxes'], plt.cm.viridis(np.linspace(0, 1, len(error_by_bin)))):
                patch.set_facecolor(color)
            ax6.set_xlabel('True Value Quantiles', fontsize=12)
            ax6.set_ylabel('Relative Error (%)', fontsize=12)
            ax6.set_title('Error Distribution by Value Range', fontsize=12, fontweight='bold')
            ax6.grid(True, alpha=0.3, axis='y')
            ax6.tick_params(axis='x', rotation=45)

            # 7. 性能指标表
            ax7 = fig.add_subplot(gs[2, 2])
            ax7.axis('off')

            # 计算各种指标
            rmse = np.sqrt(mean_squared_error(y_true, y_pred))
            mae = mean_absolute_error(y_true, y_pred)
            r2 = r2_score(y_true, y_pred)
            mape = np.mean(np.abs(residuals_rel))  # Mean Absolute Percentage Error
            rmspe = np.sqrt(np.mean((residuals / y_true) ** 2)) * 100

            metrics_text = f"""
            Performance Metrics:
            ────────────────────
            RMSE:  {rmse:.3e}
            MAE:   {mae:.3e}
            R²:    {r2:.4f}
            MAPE:  {mape:.2f}%
            RMSPE: {rmspe:.2f}%

            Residual Statistics:
            ────────────────────
            Mean:    {residuals.mean():.3e}
            Std:     {residuals.std():.3e}
            Skewness:{stats.skew(residuals):.3f}
            Kurtosis:{stats.kurtosis(residuals):.3f}
            """

            ax7.text(0.1, 0.9, metrics_text, transform=ax7.transAxes,
                     fontsize=10, verticalalignment='top', fontfamily='monospace',
                     bbox=dict(boxstyle='round', facecolor='lightgray', alpha=0.8))

            plt.suptitle(f'{title} - Comprehensive Analysis', fontsize=16, fontweight='bold', y=1.02)
            plt.tight_layout()

            if save_path:
                plt.savefig(save_path, dpi=300, bbox_inches='tight')
                print(f"Prediction analysis plot saved to {save_path}")
            plt.show()

        def plot_model_comparison(self, results: Dict, save_path: str = 'model_comparison.png'):
            """
            比较多个模型的性能

            Args:
                results: 包含多个模型结果的字典
                save_path: 保存路径
            """
            model_names = list(results.keys())
            metrics = ['RMSE', 'MAE', 'R2']

            fig, axes = plt.subplots(1, 3, figsize=(15, 5))

            for idx, metric in enumerate(metrics):
                ax = axes[idx]
                values = []
                stds = []

                for model_name in model_names:
                    metric_values = []
                    for repeat in results[model_name]['metrics']:
                        if 'val' in repeat:
                            metric_values.append(repeat['val'][metric])
                        elif 'test' in repeat:
                            metric_values.append(repeat['test'][metric])
                        else:
                            metric_values.append(repeat[metric])

                    values.append(np.mean(metric_values))
                    stds.append(np.std(metric_values))

                # 绘制条形图
                bars = ax.bar(range(len(model_names)), values, yerr=stds,
                              capsize=5, color=self.colors[:len(model_names)],
                              alpha=0.7, edgecolor='black', linewidth=1.5)

                # 添加数值标签
                for bar, val in zip(bars, values):
                    ax.text(bar.get_x() + bar.get_width() / 2, bar.get_height() + max(stds) * 0.1,
                            f'{val:.4f}', ha='center', va='bottom', fontsize=10)

                ax.set_xticks(range(len(model_names)))
                ax.set_xticklabels(model_names, rotation=45, ha='right')
                ax.set_ylabel(metric, fontsize=12)
                ax.set_title(f'{metric} Comparison', fontsize=14, fontweight='bold')
                ax.grid(True, alpha=0.3, axis='y')

            plt.tight_layout()
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            plt.show()
            print(f"Model comparison plot saved to {save_path}")

        def plot_feature_importance(self, model, feature_names: List[str],
                                    X: np.ndarray, y: np.ndarray,
                                    save_path: str = 'feature_importance.png'):
            """
            绘制特征重要性（适用于有feature_importances_属性的模型）

            Args:
                model: 训练好的模型
                feature_names: 特征名称列表
                X: 输入特征
                y: 目标变量
                save_path: 保存路径
            """
            fig, axes = plt.subplots(1, 2, figsize=(14, 6))

            # 方法1：如果模型有feature_importances_属性
            if hasattr(model, 'feature_importances_'):
                importances = model.feature_importances_
                indices = np.argsort(importances)[::-1]

                ax = axes[0]
                ax.barh(range(len(importances)), importances[indices],
                        color=self.colors[0], alpha=0.7)
                ax.set_yticks(range(len(importances)))
                ax.set_yticklabels([feature_names[i] for i in indices])
                ax.set_xlabel('Importance', fontsize=12)
                ax.set_title('Feature Importance (Model-based)', fontsize=14, fontweight='bold')
                ax.invert_yaxis()
                ax.grid(True, alpha=0.3, axis='x')

            # 方法2：使用排列重要性
            from sklearn.inspection import permutation_importance

            if hasattr(model, 'predict'):
                # 对于PyTorch模型，需要包装
                if isinstance(model, torch.nn.Module):
                    def predict_func(X):
                        model.eval()
                        with torch.no_grad():
                            X_tensor = torch.tensor(X, dtype=torch.float32).to(next(model.parameters()).device)
                            return model(X_tensor).cpu().numpy().flatten()

                    result = permutation_importance(predict_func, X, y, n_repeats=10, random_state=42)
                else:
                    result = permutation_importance(model, X, y, n_repeats=10, random_state=42)

                importances = result.importances_mean
                std = result.importances_std
                indices = np.argsort(importances)[::-1]

                ax = axes[1]
                ax.barh(range(len(importances)), importances[indices],
                        xerr=std[indices], capsize=3, color=self.colors[1], alpha=0.7)
                ax.set_yticks(range(len(importances)))
                ax.set_yticklabels([feature_names[i] for i in indices])
                ax.set_xlabel('Permutation Importance', fontsize=12)
                ax.set_title('Feature Importance (Permutation-based)', fontsize=14, fontweight='bold')
                ax.invert_yaxis()
                ax.grid(True, alpha=0.3, axis='x')

            plt.tight_layout()
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            plt.show()
            print(f"Feature importance plot saved to {save_path}")

        def plot_learning_curves(self, train_sizes: List[int], train_scores: List[float],
                                 val_scores: List[float], save_path: str = 'learning_curves.png'):
            """
            绘制学习曲线

            Args:
                train_sizes: 训练集大小列表
                train_scores: 训练集分数
                val_scores: 验证集分数
                save_path: 保存路径
            """
            fig, ax = plt.subplots(figsize=(10, 6))

            ax.plot(train_sizes, train_scores, 'o-', label='Training Score',
                    color='blue', linewidth=2, markersize=8)
            ax.plot(train_sizes, val_scores, 's-', label='Validation Score',
                    color='red', linewidth=2, markersize=8)

            # 添加误差带（如果有标准差）
            ax.fill_between(train_sizes,
                            np.array(train_scores) - np.std(train_scores),
                            np.array(train_scores) + np.std(train_scores),
                            alpha=0.2, color='blue')
            ax.fill_between(train_sizes,
                            np.array(val_scores) - np.std(val_scores),
                            np.array(val_scores) + np.std(val_scores),
                            alpha=0.2, color='red')

            ax.set_xlabel('Training Set Size', fontsize=12)
            ax.set_ylabel('Score (R²)', fontsize=12)
            ax.set_title('Learning Curves', fontsize=14, fontweight='bold')
            ax.legend(loc='best')
            ax.grid(True, alpha=0.3)

            plt.tight_layout()
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            plt.show()
            print(f"Learning curves plot saved to {save_path}")

        def plot_error_heatmap(self, y_true: np.ndarray, y_pred: np.ndarray,
                               save_path: str = 'error_heatmap.png'):
            """
            绘制误差热力图（2D密度图）

            Args:
                y_true: 真实值
                y_pred: 预测值
                save_path: 保存路径
            """
            fig, ax = plt.subplots(figsize=(10, 8))

            # 计算2D直方图
            hist, xedges, yedges = np.histogram2d(y_true, y_pred, bins=50)

            # 绘制热力图
            im = ax.imshow(hist.T, origin='lower', aspect='auto',
                           extent=[xedges[0], xedges[-1], yedges[0], yedges[-1]],
                           cmap='hot', alpha=0.8)

            # 添加颜色条
            cbar = plt.colorbar(im, ax=ax)
            cbar.set_label('Count', fontsize=12)

            # 添加完美预测线
            min_val = min(y_true.min(), y_pred.min())
            max_val = max(y_true.max(), y_pred.max())
            ax.plot([min_val, max_val], [min_val, max_val], 'b--', linewidth=2, label='Perfect Prediction')

            ax.set_xlabel('True Values', fontsize=12)
            ax.set_ylabel('Predicted Values', fontsize=12)
            ax.set_title('Error Heatmap (True vs Predicted)', fontsize=14, fontweight='bold')
            ax.legend()

            plt.tight_layout()
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            plt.show()
            print(f"Error heatmap saved to {save_path}")

        def plot_all_results(self, model_name: str, y_true: np.ndarray, y_pred: np.ndarray,
                             history: Dict = None, save_dir: str = './plots/'):
            """
            绘制所有可视化结果的综合函数

            Args:
                model_name: 模型名称
                y_true: 真实值
                y_pred: 预测值
                history: 训练历史（可选）
                save_dir: 保存目录
            """
            # 创建保存目录
            os.makedirs(save_dir, exist_ok=True)

            # 1. 预测分析图
            self.plot_prediction_analysis(
                y_true, y_pred,
                title=f'{model_name} - Prediction Analysis',
                save_path=os.path.join(save_dir, f'{model_name}_prediction_analysis.png')
            )

            # 2. 误差热力图
            self.plot_error_heatmap(
                y_true, y_pred,
                save_path=os.path.join(save_dir, f'{model_name}_error_heatmap.png')
            )

            # 3. 训练历史（如果有）
            if history:
                self.plot_training_history(
                    history,
                    save_path=os.path.join(save_dir, f'{model_name}_training_history.png')
                )

            print(f"\nAll plots for {model_name} saved to {save_dir}")

    # ============================================================================
    # 8. 主流程
    # ============================================================================
    class ModelComparisonPipeline:
        """模型比较主流程"""

        def __init__(self, config: Config):
            self.config = config
            self.trainer = ModelTrainer(config)
            # self.oat_analyzer = OATAnalyzer(config)
            self.plotter = Plotter()

            # 设置随机种子
            self._set_seed()

        def _set_seed(self):
            np.random.seed(self.config.seed)
            torch.manual_seed(self.config.seed)
            if torch.cuda.is_available():
                torch.cuda.manual_seed_all(self.config.seed)

        def load_data(self) -> Tuple[np.ndarray, np.ndarray]:
            """加载完整数据集（从清洗后的CSV文件）"""
            print("Loading cleaned data...")

            df = pd.read_csv(self.config.data_file)

            # 使用配置中指定的列索引
            X_full = df.iloc[:, self.config.cols_to_keep].values

            # Nact现在是索引19（原始），但在删除列后，它的位置会变化
            # 由于我们保留了原始列的顺序，Nact仍在索引19
            # 但注意：cols_to_keep只包含输入特征，不包括Nact
            # 所以需要单独获取Nact列
            y_full = df['Nact'].values  # 或者 df.iloc[:, 19].values

            print(f"  Total samples: {len(X_full)}")
            print(f"  Input dimensions: {X_full.shape[1]}")
            print(f"  Target: Nact")
            print(f"  Target range: [{y_full.min():.2e}, {y_full.max():.2e}]")

            return X_full, y_full

        def run(self, models: List[BaseModel]) -> Dict:
            """运行完整的模型比较流程（增强可视化）"""

            # 1. 加载数据
            X_full, y_full = self.load_data()

            # 2. 训练和评估所有模型
            print("\n" + "=" * 80)
            print("Training and evaluating models...")
            print("=" * 80)

            all_results = {}
            all_predictions = {}  # 保存预测结果用于可视化

            for model in models:
                model_name = model.get_name()
                print(f"\n{'=' * 50}")
                print(f"Model: {model_name}")
                print(f"{'=' * 50}")

                all_results[model_name] = {}
                all_predictions[model_name] = {}

                for n_samples in self.config.train_sizes:
                    print(f"\n  Training size: {n_samples}")
                    all_results[model_name][n_samples] = {'models': [], 'metrics': []}

                    for repeat in range(self.config.n_repeats):
                        print(f"    Repeat {repeat + 1}/{self.config.n_repeats}")

                        # 训练和评估
                        result = self.trainer.train_and_evaluate(
                            model, X_full, y_full, n_samples, repeat
                        )

                        all_results[model_name][n_samples]['models'].append(result['model'])
                        all_results[model_name][n_samples]['metrics'].append(result['metrics'])

                        # 保存预测结果
                        if 'y_val_true' in result:
                            key = f'N{n_samples}_rep{repeat}'
                            all_predictions[model_name][key] = {
                                'true': result['y_val_true'],
                                'pred': result['y_val_pred']
                            }

                        # 打印指标
                        val_metrics = result['metrics']['val']
                        print(f"      Val RMSE: {val_metrics['RMSE']:.4f}, "
                              f"MAE: {val_metrics['MAE']:.4f}, "
                              f"R2: {val_metrics['R2']:.4f}")

            # 3. 生成综合可视化
            print("\n" + "=" * 80)
            print("Generating comprehensive visualizations...")
            print("=" * 80)

            # 为每个模型生成最佳预测的可视化
            for model_name, predictions in all_predictions.items():
                # 收集所有预测
                all_true = []
                all_pred = []
                for key, values in predictions.items():
                    all_true.extend(values['true'])
                    all_pred.extend(values['pred'])

                if all_true:
                    # 创建模型专属的可视化目录
                    save_dir = f'./visualizations/{model_name}/'
                    os.makedirs(save_dir, exist_ok=True)

                    # 绘制预测分析图
                    self.trainer.plotter.plot_prediction_analysis(
                        np.array(all_true),
                        np.array(all_pred),
                        title=f'{model_name} - Overall Performance (All Predictions)',
                        save_path=os.path.join(save_dir, 'overall_performance.png')
                    )

                    # 绘制误差热力图
                    self.trainer.plotter.plot_error_heatmap(
                        np.array(all_true),
                        np.array(all_pred),
                        save_path=os.path.join(save_dir, 'error_heatmap.png')
                    )

            # 4. 模型比较可视化
            if len(models) > 1:
                # 收集比较结果
                comparison_results = {}
                for model_name in all_results:
                    comparison_results[model_name] = {'metrics': []}
                    for n_samples in self.config.train_sizes:
                        for repeat_result in all_results[model_name][n_samples]['metrics']:
                            comparison_results[model_name]['metrics'].append(repeat_result['val'])

                # 绘制模型比较图
                self.trainer.plotter.plot_model_comparison(
                    comparison_results,
                    save_path='./visualizations/model_comparison.png'
                )

            # 5. 学习曲线（如果有多个训练集大小）
            if len(self.config.train_sizes) > 1:
                for model_name in all_results:
                    train_sizes = []
                    val_scores = []
                    for n_samples in sorted(self.config.train_sizes):
                        scores = []
                        for repeat_result in all_results[model_name][n_samples]['metrics']:
                            scores.append(repeat_result['val']['R2'])
                        train_sizes.append(n_samples)
                        val_scores.append(np.mean(scores))

                    self.trainer.plotter.plot_learning_curves(
                        train_sizes,
                        [1.0] * len(train_sizes),  # 理想训练分数
                        val_scores,
                        save_path=f'./visualizations/{model_name}/learning_curves.png'
                    )

            print("\n" + "=" * 80)
            print("All visualizations completed!")
            print("=" * 80)

            return all_results

    # ============================================================================
    # 9. 模型加载函数（新增）
    # ============================================================================
    def load_saved_model(model_path: str, device='cpu'):
        """
        加载保存的模型

        Args:
            model_path: 模型文件路径（.pkl文件或.pth文件）
            device: 设备 ('cpu' 或 'cuda')

        Returns:
            加载的模型对象
        """
        import pickle

        if model_path.endswith('.pkl'):
            with open(model_path, 'rb') as f:
                model = pickle.load(f)
            return model
        elif model_path.endswith('.pth'):
            # 需要重新创建模型结构
            checkpoint = torch.load(model_path, map_location=device)
            model_config = checkpoint['model_config']

            # 重新创建模型
            model = EnhancedDNNModel(
                input_dim=model_config['input_dim'],
                n_epochs=model_config['n_epochs'],
                learning_rate=model_config['learning_rate'],
                weight_decay=model_config['weight_decay'],
                batch_size=model_config['batch_size'],
                patience=model_config['patience']
            )

            # 加载权重
            model.model = AdaptiveResidualNet(input_dim=model_config['input_dim']).to(device)
            model.model.load_state_dict(checkpoint['model_state_dict'])
            model.device = torch.device(device)

            return model
        else:
            raise ValueError(f"Unsupported file format: {model_path}")



    # ============================================================================
    # 9. 使用示例
    # ============================================================================
    def main():
        """主函数 - 示例用法"""

        # 配置参数
        config = Config()
        config.train_sizes =[19632]# [100, 500, 1000, 5000]  # 可自定义
        config.n_repeats = 3  # 每个样本量重复3次
        config.output_figure = 'OAT_comparison_cleaned_data.png'

        # 创建可视化目录
        os.makedirs('./visualizations', exist_ok=True)
        os.makedirs('./saved_models', exist_ok=True)

        # 定义要比较的模型（易于添加新模型）
        models = [
            EnhancedDNNModel(input_dim=15, n_epochs=1000, batch_size=256, patience=10,
                             learning_rate=3e-4, weight_decay=1e-2
                             ),  # 适合中等样本
        ]

        # 运行流程
        pipeline = ModelComparisonPipeline(config)
        training_results= pipeline.run(models) #, oat_results

        # 选择最佳模型
        best_r2 = -np.inf
        best_model_info = None

        for model_name, size_dict in training_results.items():
            for n_samples, data in size_dict.items():
                for repeat_idx, metrics in enumerate(data['metrics']):
                    val_r2 = metrics['val']['R2']
                    if val_r2 > best_r2:
                        best_r2 = val_r2
                        best_model_info = {
                            'model_name': model_name,
                            'n_samples': n_samples,
                            'repeat': repeat_idx,
                            'metrics': metrics,
                            'model': data['models'][repeat_idx]
                        }

        print(f"\n{'=' * 60}")
        print(f"BEST MODEL SELECTED:")
        print(f"  Model: {best_model_info['model_name']}")
        print(f"  Training samples: {best_model_info['n_samples']}")
        print(f"  Validation R²: {best_r2:.4f}")
        print(f"  Validation RMSE: {best_model_info['metrics']['val']['RMSE']:.4f}")
        print(f"  Validation MAE: {best_model_info['metrics']['val']['MAE']:.4f}")
        print(f"{'=' * 60}")

        # 保存最佳模型的信息
        best_model_path = './saved_models/best_model_info.txt'
        with open(best_model_path, 'w') as f:
            f.write(f"Best Model: {best_model_info['model_name']}\n")
            f.write(f"Training samples: {best_model_info['n_samples']}\n")
            f.write(f"Validation R²: {best_r2:.6f}\n")
            f.write(f"Validation RMSE: {best_model_info['metrics']['val']['RMSE']:.6f}\n")
            f.write(f"Validation MAE: {best_model_info['metrics']['val']['MAE']:.6f}\n")
            f.write(f"Training time: {best_model_info['metrics']['training_time']:.2f}s\n")

        print(f"\nBest model info saved to: {best_model_path}")
        print(f"All models saved to: ./saved_models/")

    if __name__ == "__main__":
        main()



def model_UKESM1_sensi():
    """
    ===============================================================================
    MCB全球敏感性分析 - 完整代码
    利用两个DNN模型（无MCB的3-mode模型 + 有MCB的3+1-mode模型）
    对UKESM1数据进行全球MCB敏感性分析
    ===============================================================================
    """

    import numpy as np
    import xarray as xr
    import pandas as pd
    import matplotlib.pyplot as plt
    import cartopy.crs as ccrs
    import cartopy.feature as cfeature
    from matplotlib.colors import TwoSlopeNorm
    from scipy.stats import qmc
    import pickle
    import torch
    import torch.nn as nn
    from sklearn.preprocessing import RobustScaler, StandardScaler
    import warnings
    import os
    import json
    warnings.filterwarnings('ignore')

    # 设置绘图风格
    plt.style.use('seaborn-v0_8-darkgrid')

    # =============================================================================
    # 第一部分：DNN模型定义（与训练时保持一致）
    # =============================================================================

    class AdaptiveResidualNet(nn.Module):
        """自适应残差网络 - 与训练时相同的架构"""

        def __init__(self, input_dim=12):  # 默认12，会根据加载的模型自动调整
            super().__init__()
            self.fc1 = nn.Linear(input_dim, 128)
            self.norm1 = nn.LayerNorm(128)
            self.fc2 = nn.Linear(128, 256)
            self.norm2 = nn.LayerNorm(256)
            self.fc3 = nn.Linear(256, 128)
            self.norm3 = nn.LayerNorm(128)
            self.fc4 = nn.Linear(128, 1)

            self.act = nn.SiLU()
            self.dropout = nn.Dropout(0.1)

            self.res_adapt = nn.Linear(input_dim, 128)
            self.gate = nn.Sequential(
                nn.Linear(input_dim, 32),
                nn.SiLU(),
                nn.Linear(32, 1),
                nn.Sigmoid()
            )

        def forward(self, x):
            identity = self.res_adapt(x)
            gate_value = self.gate(x)

            out = self.act(self.norm1(self.fc1(x)))
            out = self.dropout(out)
            out = self.fc2(out)
            out = self.norm2(out)
            out = self.act(out)
            out = self.dropout(out)
            out = self.fc3(out)
            out = self.norm3(out)
            out = self.act(out + gate_value * identity)
            out = self.fc4(out)
            return out.squeeze()

    # =============================================================================
    # 第二部分：DNN模型加载类
    # =============================================================================

    class MCBEmulator:
        """
        MCB DNN Emulator类
        封装无MCB模型（12个输入）和有MCB模型（16个输入）
        注意：根据你的实际模型输入维度：
        - 无MCB: 12个输入 (N_ait, R_ait, N_acc, R_acc, N_coa, R_coa,
                           temperature, pressure, updraft,
                           ait_maf, acc_maf, coa_maf)
        - 有MCB: 16个输入 (上述12个 + N_mcb, R_mcb, GSD_mcb, mcb_maf)
        """

        def __init__(self, model_3mode_dir, model_4mode_dir):
            """
            初始化emulator

            Parameters:
            -----------
            model_3mode_dir : str
                无MCB模型目录路径（包含权重文件和预处理器）
            model_4mode_dir : str
                有MCB模型目录路径（包含权重文件和预处理器）
            """
            self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
            print(f"Using device: {self.device}")

            # 加载无MCB模型（12个输入）
            print(f"\n加载无MCB模型: {model_3mode_dir}")
            self.model_bg, self.scaler_X_bg, self.scaler_y_bg = self._load_model(
                model_3mode_dir, input_dim=12
            )

            # 加载有MCB模型（15个输入）- 修改为15
            print(f"\n加载有MCB模型: {model_4mode_dir}")
            self.model_mcb, self.scaler_X_mcb, self.scaler_y_mcb = self._load_model(
                model_4mode_dir, input_dim=15  # 从16改为15
            )

            # 定义特征名称和索引
            self._define_features()

            print(f"\n模型加载完成!")
            print(f"  无MCB模型输入维度: {len(self.bg_features)}")
            print(f"  有MCB模型输入维度: {len(self.all_features)}")

        def _load_model(self, model_dir, input_dim):
            """
            加载保存的模型和预处理器

            Parameters:
            -----------
            model_dir : str
                模型目录路径
            input_dim : int
                模型输入维度
            """
            # 查找最新的模型权重文件
            weight_files = [f for f in os.listdir(model_dir) if f.endswith('_weights.pth')]
            if not weight_files:
                raise FileNotFoundError(f"No weight files found in {model_dir}")

            # 选择最新的权重文件（或你可以指定具体文件）
            weight_file = sorted(weight_files)[-1]
            weight_path = os.path.join(model_dir, weight_file)
            print(f"  加载权重文件: {weight_file}")

            # 加载模型权重
            model = AdaptiveResidualNet(input_dim=input_dim).to(self.device)
            checkpoint = torch.load(weight_path, map_location=self.device, weights_only=False)

            if 'model_state_dict' in checkpoint:
                model.load_state_dict(checkpoint['model_state_dict'])
                print(f"  模型配置: {checkpoint.get('model_config', {})}")
            else:
                model.load_state_dict(checkpoint)

            model.eval()

            # 查找预处理器文件
            preprocessor_files = [f for f in os.listdir(model_dir) if f.endswith('_preprocessor.pkl')]
            scaler_X = None
            scaler_y = None

            if preprocessor_files:
                preprocessor_file = sorted(preprocessor_files)[-1]
                preprocessor_path = os.path.join(model_dir, preprocessor_file)
                print(f"  加载预处理器: {preprocessor_file}")

                with open(preprocessor_path, 'rb') as f:
                    preprocessor_data = pickle.load(f)
                    scaler_X = preprocessor_data['scaler_X']
                    scaler_y = preprocessor_data['scaler_y']
                    log_cols = preprocessor_data.get('log_cols', [0, 2, 4, 6])
                    print(f"  对数变换列: {log_cols}")
            else:
                print("  警告: 未找到预处理器文件，将不使用标准化")

            return model, scaler_X, scaler_y

        def _define_features(self):
            """定义输入特征名称（必须与模型训练时的顺序一致）"""

            # 背景特征（12个）- 无MCB模型输入
            self.bg_features = [
                'N_ait', 'R_ait',  # 0,1 - 爱根核模态
                'N_acc', 'R_acc',  # 2,3 - 积聚模态
                'N_coa', 'R_coa',  # 4,5 - 粗粒子模态
                'temperature',  # 6 - 温度
                'pressure',  # 7 - 气压
                'updraft',  # 8 - 上升气流
                'ait_maf',  # 9 - 爱根核溶解度
                'acc_maf',  # 10 - 积聚模态溶解度
                'coa_maf'  # 11 - 粗粒子溶解度
            ]

            # MCB相关变量（3个）- 没有 mcb_maf
            self.mcb_features = [
                'N_mcb',  # 注入浓度 (m⁻³)
                'R_mcb',  # 注入粒径 (µm)
                'GSD_mcb'  # 几何标准差
            ]

            # 完整特征（15个）- 有MCB模型输入
            # 顺序: N_ait, R_ait, N_acc, R_acc, N_coa, R_coa,
            #       N_mcb, R_mcb, GSD_mcb,
            #       temperature, pressure, updraft,
            #       ait_maf, acc_maf, coa_maf
            self.all_features = [
                'N_ait', 'R_ait',  # 0,1
                'N_acc', 'R_acc',  # 2,3
                'N_coa', 'R_coa',  # 4,5
                'N_mcb', 'R_mcb', 'GSD_mcb',  # 6,7,8
                'temperature', 'pressure', 'updraft',  # 9,10,11
                'ait_maf', 'acc_maf', 'coa_maf'  # 12,13,14
            ]

            # 定义需要对数变换的特征索引（相对于all_features）
            # N_ait(0), N_acc(2), N_coa(4), N_mcb(6) 需要log变换
            self.log_idx_mcb = [0, 2, 4, 6]

            # 对于无MCB模型，需要对数变换的索引
            self.log_idx_bg = [0, 2, 4]

            # 打印特征顺序用于验证
            print("\n有MCB模型输入特征顺序 (15个输入):")
            for idx, feat in enumerate(self.all_features):
                print(f"  {idx}: {feat}")

        def _preprocess_input(self, X, for_mcb=False):
            """
            预处理输入数据
            """
            X = np.array(X, dtype=np.float32)
            if X.ndim == 1:
                X = X.reshape(1, -1)

            # 选择正确的scaler和log索引
            if for_mcb:
                scaler = self.scaler_X_mcb
                log_idx = self.log_idx_mcb  # [0, 2, 4, 6]
            else:
                scaler = self.scaler_X_bg
                log_idx = self.log_idx_bg  # [0, 2, 4]

            # 应用对数变换
            X_transformed = X.copy()
            for idx in log_idx:
                if idx < X.shape[1]:
                    # 确保非负
                    X_transformed[:, idx] = np.log1p(np.maximum(X_transformed[:, idx], 0))
                    # print(
                    #     f"    Applied log1p to feature index {idx} (value range: {X[:, idx].min():.2e} to {X[:, idx].max():.2e})")

            # 标准化
            if scaler is not None:
                X_scaled = scaler.transform(X_transformed)
            else:
                X_scaled = X_transformed

            return torch.tensor(X_scaled, dtype=torch.float32).to(self.device)

        def _postprocess_output(self, y_scaled, for_mcb=False):
            """后处理输出（逆变换）"""
            scaler = self.scaler_y_mcb if for_mcb else self.scaler_y_bg

            if scaler is not None:
                y_log = scaler.inverse_transform(y_scaled.reshape(-1, 1)).flatten()
                y_orig = np.expm1(y_log)
            else:
                y_orig = y_scaled

            return y_orig

        def predict_bg(self, X_env):
            """
            预测无喷洒的Nact（使用12个背景变量）

            Parameters:
            -----------
            X_env : array-like, shape (n_samples, 12)
                环境输入（12个背景变量）
                顺序: N_ait, R_ait, N_acc, R_acc, N_coa, R_coa,
                      temperature, pressure, updraft,
                      ait_maf, acc_maf, coa_maf

            Returns:
            --------
            Nact_bg : array, shape (n_samples,)
                基线云滴数浓度 (cm⁻³)
            """
            X_env = np.array(X_env)
            if X_env.ndim == 1:
                X_env = X_env.reshape(1, -1)

            # 确保输入维度正确
            expected_dim = len(self.bg_features)
            if X_env.shape[1] != expected_dim:
                raise ValueError(f"期望{expected_dim}个输入，得到{X_env.shape[1]}个")

            X_scaled = self._preprocess_input(X_env, for_mcb=False)

            with torch.no_grad():
                pred_scaled = self.model_bg(X_scaled).cpu().numpy()

            Nact_bg = self._postprocess_output(pred_scaled, for_mcb=False)
            return Nact_bg

        def predict_mcb(self, X_env, spray_params):
            """
            预测有喷洒的Nact（使用15个输入）

            输入顺序（必须与训练时完全一致）:
            0: N_ait, 1: R_ait,
            2: N_acc, 3: R_acc,
            4: N_coa, 5: R_coa,
            6: N_mcb, 7: R_mcb, 8: GSD_mcb,
            9: temperature, 10: pressure, 11: updraft,
            12: ait_maf, 13: acc_maf, 14: coa_maf

            Parameters:
            -----------
            X_env : array-like, shape (n_samples, 12)
                环境输入（12个背景变量）
            spray_params : array-like, shape (n_samples, 3) or (3,)
                喷洒参数 [N_mcb, R_mcb, GSD_mcb]  # 注意：现在是3个参数

            Returns:
            --------
            Nact_mcb : array, shape (n_samples,)
                喷洒后的云滴数浓度 (m⁻³)
            """
            X_env = np.array(X_env)
            spray_params = np.array(spray_params)

            if X_env.ndim == 1:
                X_env = X_env.reshape(1, -1)
            if spray_params.ndim == 1:
                spray_params = spray_params.reshape(1, -1)

            # 确保输入维度正确
            if X_env.shape[1] != len(self.bg_features):
                raise ValueError(f"期望{len(self.bg_features)}个环境输入，得到{X_env.shape[1]}个")
            if spray_params.shape[1] != len(self.mcb_features):  # 现在是3个
                raise ValueError(f"期望{len(self.mcb_features)}个喷洒参数，得到{spray_params.shape[1]}个")

            # 确保样本数匹配
            n_samples = X_env.shape[0]
            if spray_params.shape[0] == 1 and n_samples > 1:
                spray_params = np.repeat(spray_params, n_samples, axis=0)

            # 拆分X_env为各个部分
            N_ait = X_env[:, 0:1]  # 索引0
            R_ait = X_env[:, 1:2]  # 索引1
            N_acc = X_env[:, 2:3]  # 索引2
            R_acc = X_env[:, 3:4]  # 索引3
            N_coa = X_env[:, 4:5]  # 索引4
            R_coa = X_env[:, 5:6]  # 索引5
            temperature = X_env[:, 6:7]  # 索引6
            pressure = X_env[:, 7:8]  # 索引7
            updraft = X_env[:, 8:9]  # 索引8
            ait_maf = X_env[:, 9:10]  # 索引9
            acc_maf = X_env[:, 10:11]  # 索引10
            coa_maf = X_env[:, 11:12]  # 索引11

            # 拆分喷洒参数（现在是3个参数）
            N_mcb = spray_params[:, 0:1]  # 注入浓度 (m⁻³)
            R_mcb = spray_params[:, 1:2]  # 注入粒径 (µm)
            GSD_mcb = spray_params[:, 2:3]  # 几何标准差

            # 按照正确的顺序拼接（15个输入，没有 mcb_maf）
            # 顺序: N_ait, R_ait, N_acc, R_acc, N_coa, R_coa,
            #       N_mcb, R_mcb, GSD_mcb,
            #       temperature, pressure, updraft,
            #       ait_maf, acc_maf, coa_maf
            X_full = np.hstack([
                N_ait, R_ait,  # 0,1
                N_acc, R_acc,  # 2,3
                N_coa, R_coa,  # 4,5
                N_mcb, R_mcb, GSD_mcb,  # 6,7,8
                temperature, pressure, updraft,  # 9,10,11
                ait_maf, acc_maf, coa_maf  # 12,13,14
            ])

            # 预处理和预测
            X_scaled = self._preprocess_input(X_full, for_mcb=True)

            with torch.no_grad():
                pred_scaled = self.model_mcb(X_scaled).cpu().numpy()

            Nact_mcb = self._postprocess_output(pred_scaled, for_mcb=True)
            return Nact_mcb

        def get_brightening(self, X_env, spray_params):
            """
            计算喷洒带来的Nact增量

            Returns:
            --------
            delta_Nact : array
                Nact增量 (cm⁻³)
            relative_enhancement : array
                相对增强倍数
            """
            Nact_bg = self.predict_bg(X_env)
            Nact_mcb = self.predict_mcb(X_env, spray_params)

            delta_Nact = Nact_mcb - Nact_bg
            relative_enhancement = delta_Nact / (Nact_bg + 1e-10)

            return delta_Nact, relative_enhancement

        def validate_input_units(self, X_env_sample):
            """
            验证输入值的单位是否正确

            Parameters:
            -----------
            X_env_sample : array, shape (12,)
                环境输入样本
            """
            print("\n" + "=" * 60)
            print("输入值单位验证（应与训练数据单位一致）:")
            print("=" * 60)
            print(f"  N_ait: {X_env_sample[0]:.2e} m⁻³  (训练数据: m⁻³)")
            print(f"  R_ait: {X_env_sample[1]:.2f} µm    (训练数据: µm)")
            print(f"  N_acc: {X_env_sample[2]:.2e} m⁻³  (训练数据: m⁻³)")
            print(f"  R_acc: {X_env_sample[3]:.2f} µm    (训练数据: µm)")
            print(f"  N_coa: {X_env_sample[4]:.2e} m⁻³  (训练数据: m⁻³)")
            print(f"  R_coa: {X_env_sample[5]:.2f} µm    (训练数据: µm)")
            print(f"  temperature: {X_env_sample[6]:.1f} K")
            print(f"  pressure: {X_env_sample[7]:.0f} Pa")
            print(f"  updraft: {X_env_sample[8]:.3f} m/s")
            print(f"  ait_maf: {X_env_sample[9]:.3f}")
            print(f"  acc_maf: {X_env_sample[10]:.3f}")
            print(f"  coa_maf: {X_env_sample[11]:.3f}")

            # 合理性检查
            print("\n合理性检查:")

            # 检查半径是否在合理范围 (0.01 - 100 µm)
            if 0.01 < X_env_sample[1] < 100:
                print(f"  ✓ R_ait = {X_env_sample[1]:.2f} µm 在合理范围内")
            else:
                print(f"  ✗ R_ait = {X_env_sample[1]:.2f} µm 超出预期范围 (0.01-100 µm)")

            if 0.05 < X_env_sample[3] < 200:
                print(f"  ✓ R_acc = {X_env_sample[3]:.2f} µm 在合理范围内")
            else:
                print(f"  ✗ R_acc = {X_env_sample[3]:.2f} µm 超出预期范围 (0.05-200 µm)")

            if 0.2 < X_env_sample[5] < 1000:
                print(f"  ✓ R_coa = {X_env_sample[5]:.2f} µm 在合理范围内")
            else:
                print(f"  ✗ R_coa = {X_env_sample[5]:.2f} µm 超出预期范围 (0.2-1000 µm)")

            # 检查数浓度是否在合理范围
            if 1 < X_env_sample[0] < 1e8:
                print(f"  ✓ N_ait = {X_env_sample[0]:.2e} m⁻³ 在合理范围内")
            else:
                print(f"  ✗ N_ait = {X_env_sample[0]:.2e} m⁻³ 可能异常")

            print("=" * 60)

    # =============================================================================
    # 第三部分：UKESM1数据加载和处理
    # =============================================================================

    class UKESMDataLoader:
        """
        UKESM1数据加载器 - 修正单位转换
        N_xxx 单位: m⁻³ (无需转换)
        R_xxx 单位: µm (需要从直径转换)
        """

        # UKESM1变量名到模型输入的映射（包含单位转换信息）
        VAR_MAPPING = {
            # 爱根核模态
            'N_ait': {
                'nc_name': 'n_KS',
                'unit_convert': lambda x: x,  # m⁻³ → m⁻³ (无需转换)
                'description': 'Aitken mode number concentration [m⁻³]'
            },
            'R_ait': {
                'nc_name': 'ddry_KS',
                'unit_convert': lambda x: (x / 2) * 1e6,  # 直径(m) → 半径(µm)
                'description': 'Aitken mode radius [µm]'
            },
            # 积聚模态
            'N_acc': {
                'nc_name': 'n_AS',
                'unit_convert': lambda x: x,  # m⁻³ → m⁻³ (无需转换)
                'description': 'Accumulation mode number concentration [m⁻³]'
            },
            'R_acc': {
                'nc_name': 'ddry_AS',
                'unit_convert': lambda x: (x / 2) * 1e6,  # 直径(m) → 半径(µm)
                'description': 'Accumulation mode radius [µm]'
            },
            # 粗粒子模态
            'N_coa': {
                'nc_name': 'n_CS',
                'unit_convert': lambda x: x,  # m⁻³ → m⁻³ (无需转换)
                'description': 'Coarse mode number concentration [m⁻³]'
            },
            'R_coa': {
                'nc_name': 'ddry_CS',
                'unit_convert': lambda x: (x / 2) * 1e6,  # 直径(m) → 半径(µm)
                'description': 'Coarse mode radius [µm]'
            },
            # 气象变量
            'temperature': {
                'nc_name': 'tempair',
                'unit_convert': lambda x: x,  # K → K
                'description': 'Temperature [K]'
            },
            'pressure': {
                'nc_name': 'air_press',
                'unit_convert': lambda x: x,  # Pa → Pa
                'description': 'Pressure [Pa]'
            },
            'updraft': {
                'nc_name': 'updraft',
                'unit_convert': lambda x: x,  # m/s → m/s
                'description': 'Updraft velocity [m/s]'
            },
            # 溶解度
            'ait_maf': {
                'nc_name': 'solub_ait_mfrac',
                'unit_convert': lambda x: x,  # unitless
                'description': 'Aitken mode soluble mass fraction'
            },
            'acc_maf': {
                'nc_name': 'solub_acc_mfrac',
                'unit_convert': lambda x: x,  # unitless
                'description': 'Accumulation mode soluble mass fraction'
            },
            'coa_maf': {
                'nc_name': 'solub_cor_mfrac',
                'unit_convert': lambda x: x,  # unitless
                'description': 'Coarse mode soluble mass fraction'
            }
        }

        def __init__(self, filepath):
            """
            Parameters:
            -----------
            filepath : str
                UKESM1输出文件路径
            """
            self.ds = xr.open_dataset(filepath)
            self._extract_variables()

        def _extract_variables(self):
            """提取所需的12个变量并应用单位转换"""

            self.variables = {}
            self.variables_raw = {}  # 保存原始数据用于调试
            missing_vars = []

            for model_name, var_info in self.VAR_MAPPING.items():
                nc_name = var_info['nc_name']
                convert_func = var_info['unit_convert']

                if nc_name in self.ds.variables:
                    raw_data = self.ds[nc_name].values
                    self.variables_raw[model_name] = raw_data
                    # 应用单位转换
                    self.variables[model_name] = convert_func(raw_data)
                    print(f"  {model_name} ({nc_name}): 单位转换完成")
                else:
                    missing_vars.append(f"{model_name} ({nc_name})")
                    # 创建占位符数组
                    if 'lat' in self.ds.dims:
                        shape = (len(self.ds.time), len(self.ds.lat), len(self.ds.lon))
                    else:
                        shape = (1, 1, 1)
                    self.variables[model_name] = np.zeros(shape)
                    self.variables_raw[model_name] = np.zeros(shape)

            if missing_vars:
                print(f"警告: 以下变量未找到，将使用零值填充: {missing_vars}")

            # 获取坐标
            self.lats = self.ds['latitude'].values if 'latitude' in self.ds else np.array([0])
            self.lons = self.ds['longitude'].values if 'longitude' in self.ds else np.array([0])
            self.times = self.ds['time'].values if 'time' in self.ds else np.array([0])

            self.n_lats = len(self.lats)
            self.n_lons = len(self.lons)
            self.n_times = len(self.times)

            print(f"\n数据加载完成: {self.n_times} 时间步 × {self.n_lats} 纬度 × {self.n_lons} 经度")
            print(f"变量列表: {list(self.variables.keys())}")

            # 打印统计信息验证单位转换
            print("\n单位转换验证:")
            for model_name, var_info in list(self.VAR_MAPPING.items())[:6]:
                data = self.variables[model_name]
                data_flat = data[~np.isnan(data)]
                if len(data_flat) > 0:
                    if 'N_' in model_name:
                        print(f"  {model_name}: {data_flat[0]:.2e} m⁻³")
                    elif 'R_' in model_name:
                        print(f"  {model_name}: {data_flat[0]:.2f} µm")
                    else:
                        print(f"  {model_name}: {data_flat[0]:.2f}")

        def extract_point(self, time_idx, lat_idx, lon_idx):
            """
            提取单个网格点的环境输入（12个变量）
            处理NaN值：如果任何变量是NaN，返回None
            """
            try:
                # 提取每个变量
                values = []
                for var_name in ['N_ait', 'R_ait', 'N_acc', 'R_acc', 'N_coa', 'R_coa',
                                 'temperature', 'pressure', 'updraft',
                                 'ait_maf', 'acc_maf', 'coa_maf']:
                    val = self.variables[var_name][time_idx, lat_idx, lon_idx]
                    values.append(val)

                X_env = np.array(values, dtype=np.float64)  # 使用 float64 避免类型问题

                # 检查是否包含NaN
                if np.any(np.isnan(X_env)):
                    return None

                return X_env

            except (IndexError, KeyError, ValueError) as e:
                return None

        def extract_point_with_units_info(self, time_idx, lat_idx, lon_idx):
            """
            提取单个网格点并返回带单位的信息（用于调试）
            """
            X_env = self.extract_point(time_idx, lat_idx, lon_idx)

            units_info = {
                'N_ait': f"{X_env[0]:.2e} m⁻³",
                'R_ait': f"{X_env[1]:.2f} µm",
                'N_acc': f"{X_env[2]:.2e} m⁻³",
                'R_acc': f"{X_env[3]:.2f} µm",
                'N_coa': f"{X_env[4]:.2e} m⁻³",
                'R_coa': f"{X_env[5]:.2f} µm",
                'temperature': f"{X_env[6]:.1f} K",
                'pressure': f"{X_env[7]:.0f} Pa",
                'updraft': f"{X_env[8]:.3f} m/s",
                'ait_maf': f"{X_env[9]:.3f}",
                'acc_maf': f"{X_env[10]:.3f}",
                'coa_maf': f"{X_env[11]:.3f}"
            }

            return X_env, units_info

        def extract_region_average(self, lat_bounds, lon_bounds, time_indices=None):
            """
            提取区域平均的环境输入

            Parameters:
            -----------
            lat_bounds : tuple
                (lat_min, lat_max)
            lon_bounds : tuple
                (lon_min, lon_max)
            time_indices : array-like or None
                时间索引，None表示所有时间平均

            Returns:
            --------
            X_env_avg : array, shape (12,)
                区域平均的环境输入（已转换单位）
            """
            lat_mask = (self.lats >= lat_bounds[0]) & (self.lats <= lat_bounds[1])
            lon_mask = (self.lons >= lon_bounds[0]) & (self.lons <= lon_bounds[1])

            lat_indices = np.where(lat_mask)[0]
            lon_indices = np.where(lon_mask)[0]

            if time_indices is None:
                time_indices = range(self.n_times)

            # 计算区域平均
            X_sum = np.zeros(12)
            count = 0

            for t in time_indices:
                for i in lat_indices:
                    for j in lon_indices:
                        X_sum += self.extract_point(t, i, j)
                        count += 1

            X_avg = X_sum / count if count > 0 else X_sum

            return X_avg

        def get_nan_statistics(self):
            """统计每个变量的NaN数量"""
            stats = {}
            for var_name, var_data in self.variables.items():
                nan_count = np.sum(np.isnan(var_data))
                total_count = var_data.size
                stats[var_name] = {
                    'nan_count': nan_count,
                    'total_count': total_count,
                    'nan_percentage': 100 * nan_count / total_count
                }
                print(f"  {var_name}: {nan_count}/{total_count} ({100 * nan_count / total_count:.1f}%) NaN")
            return stats

    # =============================================================================
    # 第四部分：敏感性分析类
    # =============================================================================

    class MCBSensitivityAnalysis:
        """
        MCB全球敏感性分析类
        """

        def __init__(self, emulator, data_loader):
            self.emulator = emulator
            self.data = data_loader

        # ========================================================================
        # 新增方法：绘制有MCB和无MCB的预测结果对比图
        # ========================================================================

        def plot_baseline_vs_mcb_comparison(self, Nact_bg, Nact_mcb, spray_params,
                                            save_prefix='mcb_comparison'):
            """
            绘制有MCB和无MCB的预测结果对比图

            Parameters:
            -----------
            Nact_bg : array, shape (n_lats, n_lons)
                无MCB预测的基线Nact
            Nact_mcb : array, shape (n_lats, n_lons)
                有MCB预测的Nact
            spray_params : array, shape (3,)
                喷洒参数 [N_mcb, R_mcb, GSD_mcb]
            save_prefix : str
                保存文件前缀
            """
            print("\n" + "=" * 60)
            print("绘制有MCB vs 无MCB预测结果对比图")
            print("=" * 60)

            # 检查数据是否有效
            if np.all(np.isnan(Nact_bg)) or np.all(np.isnan(Nact_mcb)):
                print("警告: 数据全为NaN，跳过绘图")
                return

            # 喷洒参数标签
            spray_label = f"N_mcb={spray_params[0] / 1e6:.0f} cm⁻³, " \
                          f"R_mcb={spray_params[1] * 1000 * 2:.0f} nm, " \
                          f"GSD_mcb={spray_params[2]:.2f}"

            # 创建图形 - 2x2布局
            fig = plt.figure(figsize=(18, 14))

            # ========== 子图1: 无MCB基线Nact ==========
            ax1 = plt.subplot(2, 2, 1, projection=ccrs.PlateCarree())
            self._plot_single_map(ax1, Nact_bg / 1e6,
                                  'Nact (cm⁻³)',
                                  'Baseline Nact (Without MCB)',
                                  cmap='viridis', center=None)
            ax1.set_title('(a) Baseline Nact (Without MCB)', fontsize=14, fontweight='bold')

            # ========== 子图2: 有MCB喷洒后Nact ==========
            ax2 = plt.subplot(2, 2, 2, projection=ccrs.PlateCarree())
            self._plot_single_map(ax2, Nact_mcb / 1e6,
                                  'Nact (cm⁻³)',
                                  f'MCB Nact\n{spray_label}',
                                  cmap='viridis', center=None)
            ax2.set_title('(b) MCB Nact (With Spray)', fontsize=14, fontweight='bold')

            # ========== 子图3: ΔNact (增强量) ==========
            ax3 = plt.subplot(2, 2, 3, projection=ccrs.PlateCarree())
            delta = Nact_mcb - Nact_bg
            self._plot_single_map(ax3, delta / 1e6,
                                  'ΔNact (cm⁻³)',
                                  f'Nact Enhancement\n{spray_label}',
                                  cmap='RdBu_r', center=0)
            ax3.set_title('(c) Nact Enhancement (ΔNact = MCB - Baseline)', fontsize=14, fontweight='bold')

            # ========== 子图4: 相对增强倍数 ==========
            ax4 = plt.subplot(2, 2, 4, projection=ccrs.PlateCarree())
            relative = delta / (Nact_bg + 1e-10)
            # 限制相对增强范围以便更好地可视化
            relative_plot = np.clip(relative, 0, 5)
            self._plot_single_map(ax4, relative_plot,
                                  'Relative Enhancement',
                                  f'Relative Enhancement\n{spray_label}',
                                  cmap='RdBu_r', center=1)
            ax4.set_title('(d) Relative Enhancement (Nact_mcb / Nact_bg)', fontsize=14, fontweight='bold')

            # 添加总标题
            plt.suptitle('MCB Effect on Cloud Droplet Number Concentration (Nact)',
                         fontsize=16, fontweight='bold', y=1.02)

            plt.tight_layout()

            # 保存图片
            safe_title = f'{save_prefix}_comparison'
            plt.savefig(f'{safe_title}.png', dpi=200, bbox_inches='tight')
            plt.show()
            print(f"对比图已保存: {safe_title}.png")

            # ========== 额外：绘制散点图对比 ==========
            self._plot_scatter_comparison(Nact_bg, Nact_mcb, spray_params, save_prefix)

            # ========== 额外：绘制纬度平均剖面 ==========
            self._plot_latitude_profile(Nact_bg, Nact_mcb, delta, spray_params, save_prefix)

        def _plot_single_map(self, ax, data, label, title, cmap='RdBu', center=None):
            """
            在指定的axes上绘制单个地图
            """
            # 处理缺失值
            data_plot = np.ma.masked_invalid(data)

            if data_plot.count() == 0:
                ax.text(0.5, 0.5, 'No Valid Data', transform=ax.transAxes,
                        ha='center', va='center', fontsize=14)
                return

            # 获取经度纬度
            lons = self.data.lons.copy()
            lats = self.data.lats.copy()

            # 确保经度在 -180 到 180 范围内
            if np.max(lons) > 180:
                lons = np.where(lons > 180, lons - 360, lons)
                sort_idx = np.argsort(lons)
                lons = lons[sort_idx]
                data_plot = data_plot[:, sort_idx]

            # 确保纬度从小到大排序
            if not np.all(np.diff(lats) >= 0):
                sort_idx = np.argsort(lats)
                lats = lats[sort_idx]
                data_plot = data_plot[sort_idx, :]

            # 设置颜色范数
            vmin = np.nanmin(data_plot)
            vmax = np.nanmax(data_plot)

            if center is not None:
                max_abs = max(abs(vmin - center), abs(vmax - center))
                sym_vmin = center - max_abs
                sym_vmax = center + max_abs
                norm = TwoSlopeNorm(vmin=sym_vmin, vcenter=center, vmax=sym_vmax)
            else:
                norm = None

            # 创建网格并绘制
            lon_grid, lat_grid = np.meshgrid(lons, lats)
            im = ax.pcolormesh(lon_grid, lat_grid, data_plot,
                               cmap=cmap, norm=norm,
                               transform=ccrs.PlateCarree(),
                               shading='auto')

            # 添加海岸线
            ax.add_feature(cfeature.COASTLINE, linewidth=0.5)
            ax.add_feature(cfeature.BORDERS, linewidth=0.5, alpha=0.5)

            # 添加网格线
            gl = ax.gridlines(draw_labels=True, dms=True,
                              x_inline=False, y_inline=False,
                              linewidth=0.5, alpha=0.5)
            gl.top_labels = False
            gl.right_labels = False

            ax.set_global()

            # 添加颜色条
            cbar = plt.colorbar(im, ax=ax, label=label, fraction=0.046, pad=0.04)
            cbar.ax.tick_params(labelsize=9)

            ax.set_title(title, fontsize=12)

        def _plot_scatter_comparison(self, Nact_bg, Nact_mcb, spray_params, save_prefix):
            """
            绘制基线 vs MCB的散点图对比
            """
            fig, ax = plt.subplots(figsize=(10, 8))

            # 展平数组并移除NaN
            bg_flat = Nact_bg.flatten() / 1e6
            mcb_flat = Nact_mcb.flatten() / 1e6

            valid_mask = ~(np.isnan(bg_flat) | np.isnan(mcb_flat))
            bg_valid = bg_flat[valid_mask]
            mcb_valid = mcb_flat[valid_mask]

            if len(bg_valid) == 0:
                print("没有有效数据点用于散点图")
                return

            # 计算统计信息
            correlation = np.corrcoef(bg_valid, mcb_valid)[0, 1]
            mean_bg = np.mean(bg_valid)
            mean_mcb = np.mean(mcb_valid)

            # 绘制散点图
            ax.scatter(bg_valid, mcb_valid, alpha=0.3, s=1, c='blue', edgecolors='none')

            # 添加1:1线
            max_val = max(bg_valid.max(), mcb_valid.max())
            min_val = min(bg_valid.min(), mcb_valid.min())
            ax.plot([min_val, max_val], [min_val, max_val], 'r--', linewidth=2, label='1:1 line')

            # 添加均值点
            ax.scatter(mean_bg, mean_mcb, c='red', s=200, marker='*',
                       edgecolors='black', linewidths=2, label=f'Mean: ({mean_bg:.0f}, {mean_mcb:.0f})')

            ax.set_xlabel('Baseline Nact (cm⁻³)', fontsize=12)
            ax.set_ylabel('MCB Nact (cm⁻³)', fontsize=12)
            ax.set_title(f'Baseline vs MCB Nact Comparison\n'
                         f'N_mcb={spray_params[0] / 1e6:.0f} cm⁻³, '
                         f'R_mcb={spray_params[1] * 1000 * 2:.0f} nm, '
                         f'GSD_mcb={spray_params[2]:.2f}\n'
                         f'Correlation: {correlation:.4f}, '
                         f'Mean Enhancement: {mean_mcb - mean_bg:.0f} cm⁻³',
                         fontsize=12)

            ax.grid(True, alpha=0.3)
            ax.legend(loc='best')

            plt.tight_layout()
            plt.savefig(f'{save_prefix}_scatter.png', dpi=150, bbox_inches='tight')
            plt.show()
            print(f"散点图已保存: {save_prefix}_scatter.png")

        def _plot_latitude_profile(self, Nact_bg, Nact_mcb, delta, spray_params, save_prefix):
            """
            绘制纬度平均剖面图
            """
            fig, axes = plt.subplots(1, 3, figsize=(18, 6))

            # 计算纬度平均（经向平均）
            bg_zonal = np.nanmean(Nact_bg / 1e6, axis=1)
            mcb_zonal = np.nanmean(Nact_mcb / 1e6, axis=1)
            delta_zonal = np.nanmean(delta / 1e6, axis=1)
            relative_zonal = np.nanmean(delta / (Nact_bg + 1e-10), axis=1)

            lats = self.data.lats

            # 子图1: 基线 vs MCB
            ax1 = axes[0]
            ax1.plot(lats, bg_zonal, 'b-', linewidth=2, label='Baseline Nact')
            ax1.plot(lats, mcb_zonal, 'r-', linewidth=2, label='MCB Nact')
            ax1.fill_between(lats, bg_zonal, mcb_zonal, alpha=0.3, color='purple')
            ax1.set_xlabel('Latitude (°)', fontsize=12)
            ax1.set_ylabel('Nact (cm⁻³)', fontsize=12)
            ax1.set_title('Zonal Mean Nact: Baseline vs MCB', fontsize=12)
            ax1.legend(loc='best')
            ax1.grid(True, alpha=0.3)

            # 子图2: ΔNact纬度剖面
            ax2 = axes[1]
            ax2.bar(lats, delta_zonal, width=np.abs(lats[1] - lats[0]),
                    color='green', alpha=0.7, edgecolor='black')
            ax2.set_xlabel('Latitude (°)', fontsize=12)
            ax2.set_ylabel('ΔNact (cm⁻³)', fontsize=12)
            ax2.set_title('Zonal Mean Nact Enhancement', fontsize=12)
            ax2.grid(True, alpha=0.3, axis='y')

            # 子图3: 相对增强纬度剖面
            ax3 = axes[2]
            ax3.plot(lats, relative_zonal, 'purple', linewidth=2, marker='o', markersize=4)
            ax3.axhline(y=1, color='r', linestyle='--', alpha=0.7, label='No enhancement')
            ax3.set_xlabel('Latitude (°)', fontsize=12)
            ax3.set_ylabel('Relative Enhancement', fontsize=12)
            ax3.set_title('Zonal Mean Relative Enhancement', fontsize=12)
            ax3.grid(True, alpha=0.3)
            ax3.legend(loc='best')

            # 添加总标题
            plt.suptitle(f'Latitudinal Profiles\n'
                         f'N_mcb={spray_params[0] / 1e6:.0f} cm⁻³, '
                         f'R_mcb={spray_params[1] * 1000 * 2:.0f} nm, '
                         f'GSD_mcb={spray_params[2]:.2f}',
                         fontsize=14, fontweight='bold')

            plt.tight_layout()
            plt.savefig(f'{save_prefix}_latitude_profile.png', dpi=150, bbox_inches='tight')
            plt.show()
            print(f"纬度剖面图已保存: {save_prefix}_latitude_profile.png")

        def experiment_fixed_spray(self, spray_params, output_file=None):
            """
            实验1: 固定喷洒策略，计算全球ΔNact分布
            """
            print("=" * 60)
            print("实验1: 固定喷洒策略全球分析")
            print(f"喷洒策略: N_mcb={spray_params[0]:.3f} m⁻³, "
                  f"R_mcb={spray_params[1]:.3f} µm, "
                  f"GSD_mcb={spray_params[2]:.2f}")
            print("=" * 60)

            # 初始化结果数组，用NaN填充
            delta_Nact = np.full((self.data.n_lats, self.data.n_lons), np.nan)
            relative_enhancement = np.full_like(delta_Nact, np.nan)
            Nact_bg_all = np.full_like(delta_Nact, np.nan)
            Nact_mcb_all = np.full_like(delta_Nact, np.nan)

            # 统计有效点和无效点
            valid_count = 0
            nan_count = 0

            total_points = self.data.n_lats * self.data.n_lons
            processed = 0

            print("开始计算全球网格点...")

            for i in range(self.data.n_lats):
                for j in range(self.data.n_lons):
                    processed += 1

                    # 时间平均的环境输入
                    X_env_sum = None
                    valid_time_count = 0

                    for t in range(self.data.n_times):
                        X_env_point = self.data.extract_point(t, i, j)
                        if X_env_point is not None:
                            if X_env_sum is None:
                                X_env_sum = X_env_point
                            else:
                                X_env_sum += X_env_point
                            valid_time_count += 1

                    # 如果没有有效的时间点，跳过该网格点
                    if X_env_sum is None or valid_time_count == 0:
                        nan_count += 1
                        if processed % 1000 == 0:
                            print(f"进度: {processed}/{total_points} ({100 * processed / total_points:.1f}%) - 跳过NaN点")
                        continue

                    X_env_avg = X_env_sum / valid_time_count

                    try:
                        # 预测
                        Nact_bg = self.emulator.predict_bg(X_env_avg.reshape(1, -1))[0]
                        Nact_mcb = self.emulator.predict_mcb(X_env_avg.reshape(1, -1), spray_params)[0]

                        Nact_bg_all[i, j] = Nact_bg
                        Nact_mcb_all[i, j] = Nact_mcb
                        delta_Nact[i, j] = Nact_mcb - Nact_bg
                        relative_enhancement[i, j] = delta_Nact[i, j] / (Nact_bg + 1e-10)
                        valid_count += 1

                    except Exception as e:
                        nan_count += 1

                    if processed % 1000 == 0:
                        print(
                            f"进度: {processed}/{total_points} ({100 * processed / total_points:.1f}%) - 有效点: {valid_count}")

            print(f"\n计算完成:")
            print(f"  总网格点数: {total_points}")
            print(f"  有效点: {valid_count}")
            print(f"  无效点(NaN): {nan_count}")
            print(f"  有效率: {100 * valid_count / total_points:.1f}%")

            # ========== 新增：保存数据到文件 ==========
            if valid_count > 0:
                # 创建数据字典
                save_data = {
                    'Nact_bg': Nact_bg_all,  # 基线Nact (m⁻³)
                    'Nact_mcb': Nact_mcb_all,  # MCB Nact (m⁻³)
                    'delta_Nact': delta_Nact,  # 增量 (m⁻³)
                    'relative_enhancement': relative_enhancement,  # 相对增强
                    'lats': self.data.lats,  # 纬度
                    'lons': self.data.lons,  # 经度
                    'spray_params': spray_params,  # 喷洒参数
                    'spray_params_info': {
                        'N_mcb': spray_params[0],  # m⁻³
                        'R_mcb': spray_params[1],  # µm
                        'GSD_mcb': spray_params[2]  # 无量纲
                    }
                }

                # 保存为npz文件
                np.savez('baseline_mcb_data.npz', **save_data)
                print(f"\n数据已保存到: baseline_mcb_data.npz")
                print(f"  包含变量: {list(save_data.keys())}")

                print("\n开始绘图...")

                # ========== 新增：绘制有MCB和无MCB对比图 ==========
                self.plot_baseline_vs_mcb_comparison(
                    Nact_bg_all, Nact_mcb_all, spray_params,
                    save_prefix='fixed_spray_comparison'
                )

                # 原有绘图
                self._plot_global_map(delta_Nact, 'ΔNact (m⁻³)',
                                      'Fixed Spray: Global ΔNact Distribution',
                                      cmap='RdBu_r', center=0)

                self._plot_global_map(relative_enhancement, 'Relative Enhancement',
                                      'Fixed Spray: Global Relative Enhancement',
                                      cmap='RdBu_r', center=0)
            else:
                print("警告: 没有有效数据点，跳过绘图")

            return delta_Nact, relative_enhancement, Nact_bg_all, Nact_mcb_all

        def experiment_dp_sensitivity(self, R_list=None, N_mcb_fixed=375,
                                      GSD_mcb_fixed=1.2):
            """
            实验2: 粒径敏感性分析（R_mcb）- 没有 mcb_maf

            Parameters:
            -----------
            R_list : list or None
                测试的粒径列表 (nm)
            N_mcb_fixed : float
                固定注入浓度 (cm⁻³)
            GSD_mcb_fixed : float
                固定几何标准差
            """
            if R_list is None:
                R_list_nm = [40,60, 80,100,120, 140,160,180,200, 250, 300, 350, 400]

            # 转换为模型输入单位（nm → µm）
            R_list = [r / 2 / 1000. for r in R_list_nm]

            # 转换 N_mcb 单位（cm⁻³ → m⁻³）
            N_mcb_fixed = N_mcb_fixed * 1e6

            print("=" * 60)
            print("实验2: 粒径敏感性分析")
            print(f"测试粒径: {[f'{r * 1000 * 2:.0f}' for r in R_list]} nm")
            print(f"固定: N_mcb={N_mcb_fixed / 1e6:.0f} cm⁻³, GSD_mcb={GSD_mcb_fixed}")
            print("=" * 60)

            # 初始化结果数组，用NaN填充
            optimal_R = np.full((self.data.n_lats, self.data.n_lons), np.nan)
            max_delta = np.full_like(optimal_R, np.nan)

            total_points = self.data.n_lats * self.data.n_lons
            processed = 0
            valid_count = 0
            nan_count = 0

            print("开始计算全球网格点...")

            for i in range(self.data.n_lats):
                for j in range(self.data.n_lons):
                    processed += 1

                    # 时间平均的环境输入
                    X_env_sum = None
                    valid_time_count = 0

                    for t in range(self.data.n_times):
                        X_env_point = self.data.extract_point(t, i, j)
                        if X_env_point is not None:
                            if X_env_sum is None:
                                X_env_sum = X_env_point.copy()
                            else:
                                X_env_sum += X_env_point
                            valid_time_count += 1

                    # 如果没有有效的时间点，跳过
                    if X_env_sum is None or valid_time_count == 0:
                        nan_count += 1
                        if processed % 1000 == 0:
                            print(f"进度: {processed}/{total_points} ({100 * processed / total_points:.1f}%) - 跳过NaN点")
                        continue

                    X_env_avg = X_env_sum / valid_time_count

                    try:
                        delta_list = []
                        for R in R_list:
                            # 关键修正：只传递3个参数，没有 mcb_maf
                            spray = np.array([N_mcb_fixed, R, GSD_mcb_fixed])
                            delta, _ = self.emulator.get_brightening(
                                X_env_avg.reshape(1, -1), spray
                            )
                            delta_list.append(delta[0])

                        best_idx = np.argmax(delta_list)
                        optimal_R[i, j] = R_list[best_idx] * 1000 * 2  # 转换回 nm
                        max_delta[i, j] = delta_list[best_idx]
                        valid_count += 1

                    except Exception as e:
                        nan_count += 1

                    if processed % 1000 == 0:
                        print(
                            f"进度: {processed}/{total_points} ({100 * processed / total_points:.1f}%) - 有效点: {valid_count}")

            print(f"\n计算完成:")
            print(f"  总网格点数: {total_points}")
            print(f"  有效点: {valid_count}")
            print(f"  无效点(NaN): {nan_count}")
            print(f"  有效率: {100 * valid_count / total_points:.1f}%")

            # 只在有有效数据时绘图
            if valid_count > 0:
                print("\n开始绘图...")
                # 最优粒径 - 不需要对称颜色，使用 None
                self._plot_global_map(optimal_R, 'Optimal R_mcb (nm)',
                                      'Global Distribution of Optimal Injection Radius',
                                      cmap='viridis', center=None)

                # 最大ΔNact - 使用对称颜色，center=0
                self._plot_global_map(max_delta, 'Maximum ΔNact (m⁻³)',
                                      'Maximum Brightening Potential by Radius Optimization',
                                      cmap='RdBu_r', center=0)
            else:
                print("警告: 没有有效数据点，跳过绘图")

            return optimal_R, max_delta

        # ========================================================================
        # 可视化方法
        # ========================================================================

        def _plot_global_map(self, data, label, title, cmap='RdBu', center=None):
            """
            绘制全球地图，处理NaN值和几何错误
            """
            # 检查数据是否全为NaN
            if np.all(np.isnan(data)):
                print(f"警告: {title} 数据全为NaN，跳过绘图")
                return

            try:
                fig = plt.figure(figsize=(14, 7))
                ax = plt.axes(projection=ccrs.PlateCarree())

                # 确保 data 是 2D 数组
                if data.ndim != 2:
                    print(f"警告: data 维度为 {data.ndim}，期望 2D")
                    return

                # 检查数据是否有效
                if data.shape[0] < 2 or data.shape[1] < 2:
                    print(f"警告: data shape 为 {data.shape}，太小无法绘图")
                    return

                # 处理缺失值 - 使用 masked array
                data_plot = np.ma.masked_invalid(data)

                # 检查是否有有效数据
                if data_plot.count() == 0:
                    print(f"警告: {title} 没有有效数据点，跳过绘图")
                    return

                # 获取经度纬度
                lons = self.data.lons.copy()
                lats = self.data.lats.copy()

                # 确保经度在 -180 到 180 范围内
                if np.max(lons) > 180:
                    lons = np.where(lons > 180, lons - 360, lons)
                    # 重新排序
                    sort_idx = np.argsort(lons)
                    lons = lons[sort_idx]
                    data_plot = data_plot[:, sort_idx]

                # 确保纬度从小到大排序
                if not np.all(np.diff(lats) >= 0):
                    sort_idx = np.argsort(lats)
                    lats = lats[sort_idx]
                    data_plot = data_plot[sort_idx, :]

                # 设置颜色范数
                vmin = np.nanmin(data_plot)
                vmax = np.nanmax(data_plot)

                if center is not None:
                    # 关键修改：使颜色范围对称
                    max_abs = max(abs(vmin - center), abs(vmax - center))
                    sym_vmin = center - max_abs
                    sym_vmax = center + max_abs

                    if center < sym_vmin:
                        center = sym_vmin
                    if center > sym_vmax:
                        center = sym_vmax

                    norm = TwoSlopeNorm(vmin=sym_vmin, vcenter=center, vmax=sym_vmax)
                    print(f"  颜色范围: [{sym_vmin:.2e}, {sym_vmax:.2e}], 中心: {center}")
                else:
                    norm = None

                # 使用 pcolormesh 替代 contourf（更稳定）
                # 创建网格
                lon_grid, lat_grid = np.meshgrid(lons, lats)

                # 绘制
                im = ax.pcolormesh(lon_grid, lat_grid, data_plot,
                                   cmap=cmap, norm=norm,
                                   transform=ccrs.PlateCarree(),
                                   shading='auto')

                # 添加海岸线和边框
                ax.add_feature(cfeature.COASTLINE, linewidth=0.5)
                ax.add_feature(cfeature.BORDERS, linewidth=0.5, alpha=0.5)

                # 添加网格线（简化，避免冲突）
                gl = ax.gridlines(draw_labels=True, dms=True,
                                  x_inline=False, y_inline=False,
                                  linewidth=0.5, alpha=0.5)
                gl.top_labels = False
                gl.right_labels = False

                # 设置地图范围（全球）
                ax.set_global()

                # 添加颜色条
                cbar = plt.colorbar(im, ax=ax, label=label, fraction=0.046, pad=0.04)
                cbar.ax.tick_params(labelsize=10)

                ax.set_title(title, fontsize=14, fontweight='bold')
                plt.tight_layout()

                # 保存图片
                safe_title = title.replace(' ', '_').replace('(', '').replace(')', '').replace('⁻', 'minus')
                plt.savefig(f'{safe_title}.png', dpi=150, bbox_inches='tight')
                plt.show()

                print(f"  地图已保存: {safe_title}.png")

            except Exception as e:
                print(f"绘图出错: {e}")
                print(f"  尝试使用简化绘图方式...")

                # 备用绘图方式：使用 imshow
                try:
                    fig, ax = plt.subplots(figsize=(14, 7))

                    # 使用 imshow 绘制
                    im = ax.imshow(data_plot, cmap=cmap, norm=norm,
                                   extent=[lons[0], lons[-1], lats[0], lats[-1]],
                                   aspect='auto')

                    ax.set_xlabel('Longitude')
                    ax.set_ylabel('Latitude')

                    cbar = plt.colorbar(im, ax=ax, label=label)
                    ax.set_title(title)

                    plt.tight_layout()
                    safe_title = title.replace(' ', '_').replace('(', '').replace(')', '').replace('⁻', 'minus')
                    plt.savefig(f'{safe_title}_simple.png', dpi=150, bbox_inches='tight')
                    plt.show()
                    print(f"  简化地图已保存: {safe_title}_simple.png")

                except Exception as e2:
                    print(f"  简化绘图也失败: {e2}")

    # =============================================================================
    # 第五部分：主程序
    # =============================================================================

    def main():
        """主程序入口"""

        # ========================================================================
        # 配置参数（请根据实际情况修改）
        # ========================================================================

        # 模型目录路径（根据你的实际保存路径修改）
        MODEL_3MODE_DIR = './saved_models_no_nuc/EnhancedDNN/'  # 无MCB模型目录
        MODEL_4MODE_DIR = './saved_models/EnhancedDNN/'  # 有MCB模型目录

        # UKESM1数据路径（请修改为您的实际路径）
        UKESM_DATA_PATH = '../outEA.nc'

        # ========================================================================
        # 初始化
        # ========================================================================

        print("=" * 80)
        print("MCB全球敏感性分析")
        print("=" * 80)

        # 加载数据
        print("\n[1/3] 加载UKESM1数据...")
        try:
            data_loader = UKESMDataLoader(UKESM_DATA_PATH)

            # 添加NaN统计
            print("\nNaN统计:")
            data_loader.get_nan_statistics()
        except FileNotFoundError:
            print(f"错误: 找不到数据文件 {UKESM_DATA_PATH}")
            print("请检查文件路径是否正确")
            return None

        # 验证单位转换
        print("\n验证UKESM1数据单位转换:")
        # 获取一个样本点
        sample_point, units_info = data_loader.extract_point_with_units_info(0, 0, 0)
        for var_name, value_str in units_info.items():
            print(f"  {var_name}: {value_str}")

        # 初始化emulator
        print("\n[2/3] 加载DNN模型...")
        try:
            emulator = MCBEmulator(MODEL_3MODE_DIR, MODEL_4MODE_DIR)
        except FileNotFoundError as e:
            print(f"错误: {e}")
            print("请检查模型目录路径是否正确")
            return None

         # 验证输入单位
        emulator.validate_input_units(sample_point)

        # 初始化分析器
        analyzer = MCBSensitivityAnalysis(emulator, data_loader)

        # ========================================================================
        # 运行实验
        # ========================================================================

        print("\n[3/3] 运行敏感性分析实验...")

        # 实验1: 固定喷洒策略
        print("\n>>> 运行实验1: 固定喷洒策略...")
        # 喷洒参数: [N_mcb, R_mcb, GSD_mcb] - 只有3个参数，没有 mcb_maf
        # N_mcb: 500 cm⁻³ = 500e6 m⁻³
        # R_mcb: 150 nm = 150/2/1000 = 0.075 µm
        # GSD_mcb: 1.5
        spray_default = np.array([375.0 * 1e6, 189 / 2 / 1000, 1.2])
        delta_Nact, relative, Nact_bg, Nact_mcb = analyzer.experiment_fixed_spray(spray_default)

        # 实验2: 粒径敏感性
        print("\n>>> 运行实验2: 粒径敏感性...")
        optimal_R, max_delta = analyzer.experiment_dp_sensitivity()

        # ========================================================================
        # 汇总报告
        # ========================================================================

        print("\n" + "=" * 80)
        print("分析完成！结果汇总")
        print("=" * 80)

        print(f"\n全球平均统计:")
        print(f"  平均基线 Nact: {np.nanmean(Nact_bg/1e6):.0f} cm⁻³")
        print(f"  平均喷洒后 Nact: {np.nanmean(Nact_mcb/1e6):.0f} cm⁻³")
        print(f"  平均 ΔNact: {np.nanmean(delta_Nact/1e6):.0f} cm⁻³")
        print(f"  平均相对增强: {np.nanmean(relative):.2f}")

        print(f"\n最优粒径统计:")
        print(f"  最优粒径范围: {np.nanmin(optimal_R):.0f} - {np.nanmax(optimal_R):.0f} nm")
        print(f"  最优粒径平均值: {np.nanmean(optimal_R):.0f} nm")

        # 保存结果到文件
        results = {
            'delta_Nact': delta_Nact,
            'relative_enhancement': relative,
            'Nact_bg': Nact_bg,
            'Nact_mcb': Nact_mcb,
            'optimal_R': optimal_R,
            'max_delta': max_delta
        }

        np.savez('mcb_sensitivity_results.npz', **results)
        print("\n结果已保存到: mcb_sensitivity_results.npz")

        return analyzer, results

    if __name__ == "__main__":
        analyzer, results = main()



