def predict_delta_spectrum():
    """
    ===============================================================================
    MCB云滴谱残差预测模型 - 最终严格修正版 v2.0

    基于您的全部反馈进行严格修正：

    1. ✅ 修正：relative_delta_loss 直接约束 |Δ| 而不是除以log(S_ghosh)
    2. ✅ 修正：conservation_loss 使用 mask，只计算有效区域
    3. ✅ 新增：scale-aware constraint（加权残差约束）
    4. ✅ 修正：smoothness loss 只作用于 Δ，不作用于全谱
    5. ✅ 修正：mask 在 data_loss 和 conservation_loss 中都使用
    6. ✅ 保持：log空间用exp，Δ可正可负

    核心公式：
        log_S_pred = log(S_Ghosh + ε) + Δ
        S_pred = exp(clamp(log_S_pred, -20, 20))
        Δ = ML_output（无约束，可正可负）

    设计原则：
        - Δ 本身就是相对变化，直接约束 |Δ|
        - 物理约束只作用于有效区域（mask）
        - smoothness 只约束修正项，不约束物理结构
        - scale-aware 加权，关注重要区域

    作者: Wenjun
    日期: 2026-04-14
    ===============================================================================
    """

    import torch
    import torch.nn as nn
    import torch.optim as optim
    from torch.utils.data import DataLoader, TensorDataset
    import numpy as np
    import time
    from typing import Tuple, Dict, Optional, List
    from dataclasses import dataclass

    # =============================================================================
    # 第一部分：Ghosh方案模拟器（可微分）
    # =============================================================================

    class GhoshSchemeSimulator(nn.Module):
        """
        Ghosh activation scheme模拟器
        注意：需要根据实际Ghosh scheme替换forward实现
        """

        def __init__(self, Dp_bins: np.ndarray, device: torch.device):
            super().__init__()
            self.register_buffer('Dp_bins', torch.tensor(Dp_bins, dtype=torch.float32))
            self.n_bins = len(Dp_bins) - 1
            self.Dp_center = torch.sqrt(self.Dp_bins[:-1] * self.Dp_bins[1:])
            self.epsilon = 1e-10
            self.device = device

        def forward(self, X: torch.Tensor) -> torch.Tensor:
            """计算Ghosh scheme预测的云滴谱"""
            batch_size = X.shape[0]

            # 提取关键参数（根据实际输入特征索引调整）
            updraft = X[:, 14]  # updraft [m/s]
            N_ait = X[:, 3] * 1e-6  # Aitken mode [m^-3] -> [cm^-3]
            N_acc = X[:, 6] * 1e-6  # Accumulation mode

            # 简化的激活谱（需要替换为真实Ghosh scheme）
            Dp_center = self.Dp_center.unsqueeze(0)

            # 激活分数
            logit = 5 * (torch.log(Dp_center + self.epsilon) -
                         torch.log(torch.tensor(0.05, device=X.device)) -
                         0.2 * updraft.unsqueeze(1))
            activation_fraction = torch.sigmoid(logit)

            # 组合不同模态的贡献
            spectrum = (N_ait.unsqueeze(1) * 0.3 + N_acc.unsqueeze(1) * 0.8) * activation_fraction
            spectrum = torch.clamp(spectrum, min=0)

            return spectrum

    # =============================================================================
    # 第二部分：残差预测网络（log空间，允许正负残差）
    # =============================================================================

    class ResidualSpectrumPredictor(nn.Module):
        """残差谱预测网络 - 输出Δ（log空间残差），可正可负"""

        def __init__(self, input_dim: int = 19, n_bins: int = 50,
                     hidden_dims: List[int] = [128, 256, 128]):
            super().__init__()

            self.input_dim = input_dim
            self.n_bins = n_bins

            # 构建主网络
            layers = []
            prev_dim = input_dim

            for h_dim in hidden_dims:
                layers.extend([
                    nn.Linear(prev_dim, h_dim),
                    nn.LayerNorm(h_dim),
                    nn.SiLU(),
                    nn.Dropout(0.1)
                ])
                prev_dim = h_dim

            # 输出层：线性输出（无约束，允许正负）
            layers.append(nn.Linear(prev_dim, n_bins))

            self.network = nn.Sequential(*layers)
            self.output_scale = nn.Parameter(torch.ones(1) * 0.1)

        def forward(self, x: torch.Tensor) -> torch.Tensor:
            """输出Δ（log空间残差），可正可负"""
            return self.network(x) * self.output_scale.abs()

    # =============================================================================
    # 第三部分：物理约束模块（严格修正版 v2.0）
    # =============================================================================

    class PhysicalConstraints(nn.Module):
        """
        物理约束模块 - 严格修正版 v2.0

        关键修正：
            1. ✅ relative_delta_loss：直接约束|Δ|，不除以log(S_ghosh)
            2. ✅ conservation_loss：使用mask，只计算有效区域
            3. ✅ 新增：scale-aware constraint（加权残差约束）
            4. ✅ smoothness loss：只作用于Δ，不作用于全谱
        """

        def __init__(self, Dp_bins: np.ndarray, epsilon: float = 1e-10,
                     ghosh_threshold: float = 1e-6,
                     delta_threshold: float = 2.0):  # |Δ| > 2 被惩罚（~ e^2 ≈ 7倍）
            super().__init__()
            self.register_buffer('Dp_bins', torch.tensor(Dp_bins, dtype=torch.float32))
            self.n_bins = len(Dp_bins) - 1
            self.dlogDp = torch.diff(torch.log(self.Dp_bins))
            self.epsilon = epsilon
            self.ghosh_threshold = ghosh_threshold
            self.delta_threshold = delta_threshold

        def _get_mask(self, spectrum_ghosh: torch.Tensor) -> torch.Tensor:
            """获取mask，忽略S_Ghosh≈0的区域"""
            return (spectrum_ghosh > self.ghosh_threshold).float()

        def _get_weights(self, spectrum_ghosh: torch.Tensor) -> torch.Tensor:
            """
            Scale-aware权重：让模型更关注activation peak和accumulation mode
            权重 = 归一化的S_Ghosh
            """
            S_sum = spectrum_ghosh.sum(dim=1, keepdim=True) + self.epsilon
            # weights = spectrum_ghosh / S_sum
            weights = torch.sqrt(spectrum_ghosh + self.epsilon)
            weights = weights / (weights.sum(dim=1, keepdim=True) + self.epsilon)

            return weights

        def conservation_loss(self, spectrum_pred: torch.Tensor,
                              nact_target: torch.Tensor,
                              mask: torch.Tensor) -> torch.Tensor:
            """
            质量守恒约束（修正版本）

            ⭐ 关键：积分必须用全谱，不能mask
            """
            dlogDp = self.dlogDp.to(spectrum_pred.device)

            # ✅ 正确：全谱积分
            nact_pred = torch.sum(spectrum_pred * dlogDp, dim=1)

            log_nact_pred = torch.log(nact_pred + self.epsilon)
            log_nact_target = torch.log(nact_target + self.epsilon)

            loss = nn.functional.mse_loss(log_nact_pred, log_nact_target)

            return loss

        def smoothness_loss_on_delta(self, delta_log: torch.Tensor,
                                     mask: torch.Tensor) -> torch.Tensor:
            """
            ⭐ 关键修正：smoothness只作用于Δ，不作用于全谱

            理由：
                - activation spectrum 本身在critical size附近是陡峭的
                - 不应该抑制真实的物理结构
                - 只约束修正项的平滑性
            """
            # 计算log空间的一阶差分
            # delta_diff = delta_log[:, 1:] - delta_log[:, :-1]

            dlogDp = self.dlogDp.to(delta_log.device)
            delta_diff = (delta_log[:, 1:] - delta_log[:, :-1]) / dlogDp

            # 只在mask区域计算
            mask_aligned = mask[:, 1:] * mask[:, :-1]

            # 使用Huber loss
            loss = nn.functional.huber_loss(
                delta_diff * mask_aligned,
                torch.zeros_like(delta_diff) * mask_aligned,
                delta=1.0
            )

            return loss

        def relative_delta_loss(self, delta_log: torch.Tensor,
                                mask: torch.Tensor) -> torch.Tensor:
            """
            ⭐ 关键修正：直接约束|Δ|，不除以log(S_ghosh)

            物理意义：
                - Δ 本身就是相对变化（multiplicative）
                - Δ = log(S_pred / S_ghosh)
                - Δ = 0 → 无修正
                - Δ = 1 → ×e ≈ 2.7倍
                - Δ = -1 → ÷e

            约束：|Δ| < threshold（默认2，即约7倍变化）
            """
            # Hard penalty：超过阈值的部分被惩罚
            excess = torch.relu(torch.abs(delta_log) - self.delta_threshold)
            hard_penalty = torch.mean((excess ** 2) * mask)

            return hard_penalty

        def scale_aware_delta_loss(self, delta_log: torch.Tensor,
                                   spectrum_ghosh: torch.Tensor,
                                   mask: torch.Tensor) -> torch.Tensor:
            """
            ⭐ 新增：Scale-aware constraint

            目的：让模型更关注重要区域（activation peak, accumulation mode）

            权重 = 归一化的S_Ghosh
            重要区域权重高，不重要区域（tail）权重低
            """
            weights = self._get_weights(spectrum_ghosh)

            # 加权残差约束
            weighted_delta = (delta_log ** 2) * weights * mask
            loss = torch.mean(weighted_delta)

            return loss

        def positivity_loss(self, spectrum_pred: torch.Tensor) -> torch.Tensor:
            """非负约束（保险）"""
            negative_penalty = torch.relu(-spectrum_pred)
            return torch.mean(negative_penalty ** 2)

        def total_physical_loss(self, spectrum_pred: torch.Tensor,
                                spectrum_ghosh: torch.Tensor,
                                delta_log: torch.Tensor,
                                nact_target: torch.Tensor,
                                weights: Optional[Dict[str, float]] = None) -> torch.Tensor:
            """
            组合物理约束（所有约束都使用mask）
            """
            # 计算mask
            mask = self._get_mask(spectrum_ghosh)

            if weights is None:
                weights = {
                    'conservation': 1.0,
                    'smoothness_delta': 0.05,  # 弱约束，只约束Δ
                    'relative_delta': 0.2,  # 强约束：|Δ| < threshold
                    'scale_aware': 0.1,  # 新增：scale-aware约束
                    'positivity': 0.01
                }

            losses = {}
            total_loss = 0.0

            if weights.get('conservation', 0) > 0:
                cons_loss = self.conservation_loss(spectrum_pred, nact_target, mask)
                losses['conservation'] = cons_loss.item()
                total_loss += weights['conservation'] * cons_loss

            if weights.get('smoothness_delta', 0) > 0:
                smooth_loss = self.smoothness_loss_on_delta(delta_log, mask)
                losses['smoothness_delta'] = smooth_loss.item()
                total_loss += weights['smoothness_delta'] * smooth_loss

            if weights.get('relative_delta', 0) > 0:
                rel_delta_loss = self.relative_delta_loss(delta_log, mask)
                losses['relative_delta'] = rel_delta_loss.item()
                total_loss += weights['relative_delta'] * rel_delta_loss

            if weights.get('scale_aware', 0) > 0:
                scale_loss = self.scale_aware_delta_loss(delta_log, spectrum_ghosh, mask)
                losses['scale_aware'] = scale_loss.item()
                total_loss += weights['scale_aware'] * scale_loss

            if weights.get('positivity', 0) > 0:
                pos_loss = self.positivity_loss(spectrum_pred)
                losses['positivity'] = pos_loss.item()
                total_loss += weights['positivity'] * pos_loss

            self.last_losses = losses

            return total_loss

    # =============================================================================
    # 第四部分：完整的Δspectrum预测模型（最终修正版）
    # =============================================================================

    class DeltaSpectrumModel(nn.Module):
        """
        完整的Δspectrum预测模型 - 最终修正版 v2.0
        """

        def __init__(self, input_dim: int = 19, n_bins: int = 50,
                     ghosh_simulator: Optional[GhoshSchemeSimulator] = None,
                     Dp_bins: Optional[np.ndarray] = None,
                     device: torch.device = None,
                     log_clamp_min: float = -20,
                     log_clamp_max: float = 20):
            super().__init__()

            self.input_dim = input_dim
            self.n_bins = n_bins
            self.device = device or torch.device("cuda" if torch.cuda.is_available() else "cpu")
            self.epsilon = 1e-10
            self.log_clamp_min = log_clamp_min
            self.log_clamp_max = log_clamp_max

            # Ghosh scheme模拟器
            if ghosh_simulator is not None:
                self.ghosh_simulator = ghosh_simulator
            elif Dp_bins is not None:
                self.ghosh_simulator = GhoshSchemeSimulator(Dp_bins, self.device)
            else:
                raise ValueError("Either ghosh_simulator or Dp_bins must be provided")

            # 残差预测网络
            self.predictor = ResidualSpectrumPredictor(input_dim, n_bins)

            # 物理约束模块
            if Dp_bins is not None:
                self.physics = PhysicalConstraints(Dp_bins)
            else:
                self.physics = None

        def forward(self, X: torch.Tensor) -> Tuple[torch.Tensor, torch.Tensor, torch.Tensor]:
            """
            前向传播

            Returns:
                spectrum_pred: 预测的云滴谱
                spectrum_ghosh: Ghosh基线谱
                delta_log: log空间残差
            """
            # 计算Ghosh基线谱
            spectrum_ghosh = self.ghosh_simulator(X)

            # 计算log空间残差（可正可负）
            delta_log = self.predictor(X)

            # log空间组合
            log_spectrum_ghosh = torch.log(spectrum_ghosh + self.epsilon)
            log_spectrum_pred = log_spectrum_ghosh + delta_log

            # ⭐ 使用exp，不是softplus
            log_spectrum_pred_clamped = torch.clamp(
                log_spectrum_pred,
                self.log_clamp_min,
                self.log_clamp_max
            )
            spectrum_pred = torch.exp(log_spectrum_pred_clamped)
            spectrum_pred = torch.clamp(spectrum_pred, min=0)

            return spectrum_pred, spectrum_ghosh, delta_log

        def compute_loss(self, X: torch.Tensor, spectrum_true: torch.Tensor,
                         nact_true: torch.Tensor,
                         weights: Optional[Dict[str, float]] = None) -> Dict[str, torch.Tensor]:
            """计算总损失"""
            spectrum_pred, spectrum_ghosh, delta_log = self.forward(X)

            # 计算mask
            mask = (spectrum_ghosh > self.physics.ghosh_threshold).float()

            # 数据损失：在log空间计算，使用mask
            log_pred = torch.log(spectrum_pred + self.epsilon)
            log_true = torch.log(spectrum_true + self.epsilon)

            diff2 = (log_pred - log_true) ** 2

            # ✅ 用 mask 归一化（关键）
            data_loss = torch.sum(diff2 * mask) / (mask.sum() + 1e-8)

            # 物理约束损失
            phys_loss = torch.tensor(0.0, device=X.device)
            if self.physics is not None:
                if weights is None:
                    phys_weight = 0.05
                else:
                    phys_weight = weights.get('physical', 0.05)

                phys_loss = self.physics.total_physical_loss(
                    spectrum_pred, spectrum_ghosh, delta_log, nact_true, weights
                )

            # 总损失
            total_loss = data_loss + phys_weight * phys_loss

            return {
                'total_loss': total_loss,
                'data_loss': data_loss,
                'phys_loss': phys_loss,
                'spectrum_pred': spectrum_pred,
                'spectrum_ghosh': spectrum_ghosh,
                'delta_log': delta_log,
                'mask_ratio': mask.mean()
            }

    # =============================================================================
    # 第五部分：训练器（最终修正版）
    # =============================================================================

    @dataclass
    class TrainingConfig:
        """训练配置"""
        input_dim: int = 19
        n_bins: int = 50
        n_epochs: int = 300
        learning_rate: float = 3e-4
        weight_decay: float = 1e-2
        batch_size: int = 16
        patience: int = 20
        physical_weight: float = 0.05
        grad_clip: float = 1.0
        use_amp: bool = False

        # 物理约束各项权重
        conservation_weight: float = 1.0
        smoothness_delta_weight: float = 0.05  # 只约束Δ
        relative_delta_weight: float = 0.2  # |Δ| < threshold
        scale_aware_weight: float = 0.1  # 新增
        positivity_weight: float = 0.01

        # 数值稳定性参数
        log_clamp_min: float = -20
        log_clamp_max: float = 20
        ghosh_threshold: float = 1e-6
        delta_threshold: float = 2.0  # |Δ| > 2 被惩罚

    class DeltaSpectrumTrainer:
        """Δspectrum模型训练器 - 最终修正版 v2.0"""

        def __init__(self, config: TrainingConfig, Dp_bins: np.ndarray):
            self.config = config
            self.Dp_bins = Dp_bins
            self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")

            self.model = None
            self.ghosh_simulator = GhoshSchemeSimulator(Dp_bins, self.device)

            # 训练历史
            self.train_losses = []
            self.val_losses = []
            self.data_losses = []
            self.phys_losses = []
            self.mask_ratios = []
            self.delta_stats = []

            print(f"设备: {self.device}")
            print(f"输入维度: {config.input_dim}")
            print(f"粒径bin数: {config.n_bins}")
            print(f"Ghosh阈值: {config.ghosh_threshold}")
            print(f"Δ阈值: {config.delta_threshold} (超过此值被惩罚)")

        def train(self, X_train: np.ndarray, spectra_train: np.ndarray, nact_train: np.ndarray,
                  X_val: Optional[np.ndarray] = None,
                  spectra_val: Optional[np.ndarray] = None,
                  nact_val: Optional[np.ndarray] = None):
            """训练模型"""
            start_time = time.time()

            # 准备数据
            print("准备数据...")
            X_train_t = torch.tensor(X_train, dtype=torch.float32).to(self.device)
            spectra_train_t = torch.tensor(spectra_train, dtype=torch.float32).to(self.device)
            nact_train_t = torch.tensor(nact_train, dtype=torch.float32).to(self.device)

            has_val = X_val is not None
            if has_val:
                X_val_t = torch.tensor(X_val, dtype=torch.float32).to(self.device)
                spectra_val_t = torch.tensor(spectra_val, dtype=torch.float32).to(self.device)
                nact_val_t = torch.tensor(nact_val, dtype=torch.float32).to(self.device)

            # 数据加载器
            train_dataset = TensorDataset(X_train_t, spectra_train_t, nact_train_t)
            train_loader = DataLoader(train_dataset, batch_size=self.config.batch_size, shuffle=True)

            # 初始化模型
            print("初始化模型...")
            self.model = DeltaSpectrumModel(
                input_dim=self.config.input_dim,
                n_bins=self.config.n_bins,
                ghosh_simulator=self.ghosh_simulator,
                Dp_bins=self.Dp_bins,
                device=self.device,
                log_clamp_min=self.config.log_clamp_min,
                log_clamp_max=self.config.log_clamp_max
            ).to(self.device)

            if self.model.physics is not None:
                self.model.physics.ghosh_threshold = self.config.ghosh_threshold
                self.model.physics.delta_threshold = self.config.delta_threshold

            n_params = sum(p.numel() for p in self.model.parameters())
            print(f"模型参数量: {n_params:,}")

            # 优化器
            optimizer = optim.AdamW(self.model.parameters(),
                                    lr=self.config.learning_rate,
                                    weight_decay=self.config.weight_decay)
            scheduler = optim.lr_scheduler.CosineAnnealingWarmRestarts(optimizer, T_0=50, T_mult=2)

            # 损失权重
            loss_weights = {
                'physical': self.config.physical_weight,
                'conservation': self.config.conservation_weight,
                'smoothness_delta': self.config.smoothness_delta_weight,
                'relative_delta': self.config.relative_delta_weight,
                'scale_aware': self.config.scale_aware_weight,
                'positivity': self.config.positivity_weight
            }

            # 训练循环
            best_loss = float('inf')
            counter = 0
            best_state = None

            print(f"\n开始训练 ({self.config.n_epochs} epochs)...")

            for epoch in range(self.config.n_epochs):
                # 训练
                self.model.train()
                total_loss = 0
                total_data_loss = 0
                total_phys_loss = 0
                total_mask_ratio = 0
                delta_values = []

                for X_batch, spectra_batch, nact_batch in train_loader:
                    optimizer.zero_grad()

                    losses = self.model.compute_loss(X_batch, spectra_batch, nact_batch, loss_weights)
                    losses['total_loss'].backward()
                    torch.nn.utils.clip_grad_norm_(self.model.parameters(), self.config.grad_clip)
                    optimizer.step()

                    total_loss += losses['total_loss'].item()
                    total_data_loss += losses['data_loss'].item()
                    total_phys_loss += losses['phys_loss'].item()
                    total_mask_ratio += losses.get('mask_ratio', 0).item()

                    if 'delta_log' in losses:
                        delta_values.append(losses['delta_log'].detach().cpu().numpy())

                avg_train_loss = total_loss / len(train_loader)
                avg_data_loss = total_data_loss / len(train_loader)
                avg_phys_loss = total_phys_loss / len(train_loader)
                avg_mask_ratio = total_mask_ratio / len(train_loader)

                self.train_losses.append(avg_train_loss)
                self.data_losses.append(avg_data_loss)
                self.phys_losses.append(avg_phys_loss)
                self.mask_ratios.append(avg_mask_ratio)

                if delta_values:
                    all_deltas = np.concatenate(delta_values)
                    self.delta_stats.append({
                        'mean': np.mean(all_deltas),
                        'std': np.std(all_deltas),
                        'min': np.min(all_deltas),
                        'max': np.max(all_deltas),
                        'abs_mean': np.mean(np.abs(all_deltas)),
                        'exceed_ratio': np.mean(np.abs(all_deltas) > self.config.delta_threshold)
                    })

                scheduler.step()

                # 验证
                self.model.eval()
                with torch.no_grad():
                    if has_val:
                        val_losses = self.model.compute_loss(X_val_t, spectra_val_t, nact_val_t, loss_weights)
                        val_loss = val_losses['total_loss'].item()
                    else:
                        val_loss = avg_train_loss

                self.val_losses.append(val_loss)

                # 早停
                if val_loss < best_loss:
                    best_loss = val_loss
                    best_state = {k: v.cpu().clone() for k, v in self.model.state_dict().items()}
                    counter = 0
                else:
                    counter += 1

                if counter > self.config.patience:
                    print(f"      早停于 epoch {epoch}")
                    break

                if (epoch + 1) % 50 == 0 or epoch == 0:
                    delta_info = self.delta_stats[-1] if self.delta_stats else {}
                    print(f"      Epoch {epoch + 1}: Train Loss = {avg_train_loss:.6f} "
                          f"(Data: {avg_data_loss:.6f}, Phys: {avg_phys_loss:.6f}), "
                          f"Val Loss = {val_loss:.6f}")
                    print(f"        Mask ratio: {avg_mask_ratio:.3f}")
                    print(f"        Δ: mean={delta_info.get('mean', 0):.4f}, "
                          f"abs_mean={delta_info.get('abs_mean', 0):.4f}, "
                          f"exceed_ratio={delta_info.get('exceed_ratio', 0):.3f}")

            if best_state is not None:
                self.model.load_state_dict(best_state)

            self.training_time = time.time() - start_time
            print(f"\n训练完成！ 最佳验证损失: {best_loss:.6f}, 时间: {self.training_time:.2f}s")

            if self.delta_stats:
                final_delta = self.delta_stats[-1]
                print(f"  最终Δ统计: mean={final_delta['mean']:.4f}, "
                      f"abs_mean={final_delta['abs_mean']:.4f}, "
                      f"exceed_ratio={final_delta['exceed_ratio']:.3f}")

        def predict_spectrum(self, X: np.ndarray) -> np.ndarray:
            """预测云滴谱"""
            if self.model is None:
                raise ValueError("模型未训练")
            X_tensor = torch.tensor(X, dtype=torch.float32).to(self.device)
            self.model.eval()
            with torch.no_grad():
                spectrum, _, _ = self.model(X_tensor)
            return spectrum.cpu().numpy()

        def predict_nact(self, X: np.ndarray) -> np.ndarray:
            """从预测的谱计算Nact"""
            spectra = self.predict_spectrum(X)
            dlogDp = np.diff(np.log(self.Dp_bins))
            return np.sum(spectra * dlogDp, axis=1)

    if __name__ == "__main__":
        # 快速测试
        n_bins = 50
        Dp_bins = np.logspace(-2, 1, n_bins + 1)

        config = TrainingConfig(
            input_dim=19,
            n_bins=n_bins,
            n_epochs=10,  # 快速测试
            batch_size=32,
            delta_threshold=2.0
        )

        trainer = DeltaSpectrumTrainer(config, Dp_bins)
        print("\n模型初始化成功！")


def delete_unclean_fromall():
    import numpy as np
    import pandas as pd

    # 1. 读取unclean indices
    unclean_indices = []
    with open('./unclean_samples_indices.txt', 'r') as f:
        for line in f:
            line = line.strip()
            if line and not line.startswith('#') and line != 'Indices:':
                try:
                    unclean_indices.append(int(line))
                except:
                    pass

    print(f"Loaded {len(unclean_indices)} unclean indices")

    # 2. 读取CSV文件
    df = pd.read_csv('./LHSOutputs_995percent_PARSEC_new20000lhs_clean_noMCB.csv')
    print(f"Original shape: {df.shape}")

    # 3. 删除unclean行
    df_cleaned = df.drop(index=unclean_indices).reset_index(drop=True)
    print(f"Cleaned shape: {df_cleaned.shape}")

    # 4. 保存
    df_cleaned.to_csv('./LHSOutputs_995percent_PARSEC_new20000lhs_clean_noMCB_FINAL.csv', index=False)
    df_cleaned.to_csv('./LHSOutputs_995percent_PARSEC_new20000lhs_clean_noMCB_FINAL.dat',
                      sep=' ', index=False, header=False)

    print("Done! Cleaned data saved.")



def extract_UKESM1_2_csv():
    import xarray as xr
    import pandas as pd
    import numpy as np

    def extract_UKESM_to_csv_simple(nc_file_path, output_csv_path):
        """
        简化版本：使用xarray的to_dataframe方法直接转换
        去掉time、lat、lon列，只保留变量列，并删除NaN行
        添加Sample_ID作为第一列
        添加喷洒参数列（Ninj, Dp_inj, sigma_inj）

        Parameters:
        -----------
        nc_file_path : str
            NetCDF文件路径
        output_csv_path : str
            输出CSV文件路径
        """
        print("=" * 60)
        print("读取UKESM1 NetCDF文件（简化版）")
        print("=" * 60)

        # 定义需要提取的变量
        variables = [
            'air_press', 'ddry_AS', 'ddry_CS', 'ddry_KS', 'ddry_NS',
            'height', 'meansupsat_x_cldbase', 'n_AS', 'n_CS', 'n_KS', 'n_NS',
            'nact_cldrp_tot', 'tempair', 'updraft',
            'solub_nuc_mfrac', 'solub_ait_mfrac', 'solub_acc_mfrac', 'solub_cor_mfrac'
        ]

        # 喷洒参数（固定值）
        SPRAY_PARAMS = {
            'Ninj': 375,  # 注入浓度 [cm⁻³]
            'Dp_inj': 189,  # 注入粒径 [nm]
            'sigma_inj': 1.2  # 几何标准差
        }

        # 读取文件
        print(f"正在读取文件: {nc_file_path}")
        ds = xr.open_dataset(nc_file_path)

        # 打印文件信息
        print(f"\n文件维度: {dict(ds.dims)}")
        print(f"文件变量: {list(ds.variables.keys())[:10]}...")

        # 选择需要的变量（只选择存在的）
        existing_vars = [var for var in variables if var in ds.variables]
        missing_vars = [var for var in variables if var not in ds.variables]

        if missing_vars:
            print(f"\n警告: 以下变量不存在: {missing_vars}")

        print(f"\n将提取 {len(existing_vars)} 个变量")

        # 转换为DataFrame
        print("\n正在转换为DataFrame...")
        try:
            # 方法1: 直接转换
            ds_subset = ds[existing_vars]
            df = ds_subset.to_dataframe().reset_index()
        except Exception as e:
            print(f"转换出错: {e}")
            print("尝试方法2...")

            # 方法2: 逐个变量提取
            df = None
            for var in existing_vars:
                print(f"  提取变量: {var}")
                var_df = ds[var].to_dataframe().reset_index()
                if df is None:
                    df = var_df
                else:
                    # 合并DataFrame
                    common_cols = [col for col in df.columns if
                                   col in var_df.columns and col not in ['time', 'lat', 'lon', 'latitude', 'longitude']]
                    df = df.merge(var_df, on=['time', 'lat', 'lon'], how='outer')

        print(f"\n原始数据维度: {df.shape}")

        # ============================================================
        # 去掉time、lat、lon列
        # ============================================================
        print("\n去掉时间、纬度、经度列...")

        # 需要删除的列名
        cols_to_drop = []
        for col in df.columns:
            if col.lower() in ['time', 'lat', 'lon', 'latitude', 'longitude']:
                cols_to_drop.append(col)

        if cols_to_drop:
            df = df.drop(columns=cols_to_drop)
            print(f"  已删除列: {cols_to_drop}")
        else:
            print("  未找到需要删除的坐标列")

        print(f"  删除后数据维度: {df.shape}")

        # ============================================================
        # 删除包含NaN的行
        # ============================================================
        print("\n删除包含NaN的行...")

        # 记录删除前的行数
        rows_before = len(df)

        # 统计每列的NaN数量
        print("\n各列NaN统计:")
        for col in df.columns:
            nan_count = df[col].isna().sum()
            if nan_count > 0:
                print(f"  {col}: {nan_count} NaN值 ({100 * nan_count / rows_before:.2f}%)")

        # 删除包含NaN的行
        df = df.dropna()

        rows_after = len(df)
        rows_removed = rows_before - rows_after

        print(f"\n删除结果:")
        print(f"  删除前行数: {rows_before}")
        print(f"  删除后行数: {rows_after}")
        print(f"  删除行数: {rows_removed} ({100 * rows_removed / rows_before:.2f}%)")

        # ============================================================
        # 添加Sample_ID作为第一列
        # ============================================================
        print("\n添加Sample_ID列...")

        # 在开头插入Sample_ID列
        df.insert(0, 'Sample_ID', range(1, len(df) + 1))

        print(f"  已添加Sample_ID列，范围: 1 到 {len(df)}")

        # ============================================================
        # 添加喷洒参数列
        # ============================================================
        print("\n添加喷洒参数列...")

        # 添加喷洒参数列（每行都是相同的固定值）
        df['Ninj'] = SPRAY_PARAMS['Ninj']
        df['Dp_inj'] = SPRAY_PARAMS['Dp_inj']
        df['sigma_inj'] = SPRAY_PARAMS['sigma_inj']

        print(f"  已添加喷洒参数列:")
        print(f"    Ninj = {SPRAY_PARAMS['Ninj']} cm⁻³")
        print(f"    Dp_inj = {SPRAY_PARAMS['Dp_inj']} nm")
        print(f"    sigma_inj = {SPRAY_PARAMS['sigma_inj']}")

        # ============================================================
        # 可选：检查是否还有无效值
        # ============================================================
        print("\n检查是否还有无效值...")
        for col in df.columns:
            if col not in ['Sample_ID', 'Ninj', 'Dp_inj', 'sigma_inj']:  # 跳过ID和喷洒参数列
                inf_count = np.isinf(df[col]).sum()
                if inf_count > 0:
                    print(f"  {col}: {inf_count} 无穷值")
                    # 将无穷值替换为NaN并删除
                    df[col] = df[col].replace([np.inf, -np.inf], np.nan)

        # 再次删除因无穷值产生的NaN行
        if df.isna().any().any():
            # 重新删除包含NaN的行
            df = df.dropna()
            # 重新生成Sample_ID
            df['Sample_ID'] = range(1, len(df) + 1)
            print(f"  处理后数据维度: {df.shape}")

        # ============================================================
        # 保存为CSV
        # ============================================================
        print(f"\n正在保存到: {output_csv_path}")
        df.to_csv(output_csv_path, index=False)

        # 显示统计信息
        print(f"\n✅ 转换完成!")
        print(f"  最终数据维度: {df.shape}")
        print(f"  列名: {list(df.columns)}")

        # 显示前几行
        print(f"\n数据预览（前10行）:")
        print(df.head(10))

        # 显示基本统计
        print(f"\n基本统计信息:")
        print(f"  总样本数: {len(df)}")
        print(f"  环境变量数: {len(variables)}")
        print(f"  喷洒参数: 3个 (Ninj, Dp_inj, sigma_inj)")

        for col in df.columns[1:5]:  # 显示前4个变量的统计
            if col not in ['Sample_ID', 'Ninj', 'Dp_inj', 'sigma_inj']:
                print(f"  {col}: min={df[col].min():.4e}, max={df[col].max():.4e}, mean={df[col].mean():.4e}")

        # 显示喷洒参数的统计
        print(f"\n喷洒参数值:")
        print(f"  Ninj: {df['Ninj'].iloc[0]} cm⁻³ (固定值)")
        print(f"  Dp_inj: {df['Dp_inj'].iloc[0]} nm (固定值)")
        print(f"  sigma_inj: {df['sigma_inj'].iloc[0]} (固定值)")

        ds.close()

        return df

