def reshape_from_PARSEC_2_map():
    """
    从PARSEC输出的.dat文件重构二维分布图
    使用原始NetCDF文件中的经纬度信息（保持与数据相同的顺序）
    画图方法与MCBSensitivityAnalysis类保持一致
    """
    import numpy as np
    import xarray as xr
    import matplotlib.pyplot as plt
    import cartopy.crs as ccrs
    import cartopy.feature as cfeature
    from matplotlib.colors import TwoSlopeNorm
    import pandas as pd

    # ============================================================================
    # 1. 读取原始NetCDF文件，获取经纬度坐标（按行顺序）
    # ============================================================================
    print("=" * 60)
    print("重构PARSEC结果二维分布图")
    print("=" * 60)

    print("\n读取经纬度信息...")
    nc_file = '../outEA.nc'
    ds = xr.open_dataset(nc_file)

    # 提取所有变量（与导出时相同的顺序）
    variables = [
        'air_press', 'ddry_AS', 'ddry_CS', 'ddry_KS', 'ddry_NS',
        'height', 'meansupsat_x_cldbase', 'n_AS', 'n_CS', 'n_KS', 'n_NS',
        'nact_cldrp_tot', 'tempair', 'updraft',
        'solub_nuc_mfrac', 'solub_ait_mfrac', 'solub_acc_mfrac', 'solub_cor_mfrac'
    ]

    # 获取所有有效点的经纬度（与导出CSV时相同的处理方式）
    print("  提取有效网格点（与导出CSV时相同的逻辑）...")

    # 创建DataFrame并删除NaN（与extract_UKESM_to_csv_simple相同的逻辑）
    existing_vars = [var for var in variables if var in ds.variables]
    ds_subset = ds[existing_vars]
    df_coords = ds_subset.to_dataframe().reset_index()

    # 去掉time、lat、lon列
    cols_to_drop = []
    for col in df_coords.columns:
        if col.lower() in ['time', 'lat', 'lon', 'latitude', 'longitude']:
            cols_to_drop.append(col)

    if cols_to_drop:
        df_coords = df_coords.drop(columns=cols_to_drop)

    # 删除包含NaN的行（与导出时一致）
    df_coords = df_coords.dropna()

    # 现在我们需要获取每个有效点的经纬度
    # 从原始数据集中重新提取对应点的经纬度
    print("  重新构建经纬度映射...")

    # 获取维度
    times = ds['time'].values if 'time' in ds else [0]
    lats = ds['latitude'].values if 'latitude' in ds else ds['lat'].values
    lons = ds['longitude'].values if 'longitude' in ds else ds['lon'].values

    n_times = len(times)
    n_lats = len(lats)
    n_lons = len(lons)

    print(f"  原始网格: {n_times} 时间 × {n_lats} 纬度 × {n_lons} 经度")

    # 遍历所有网格点，检查是否为有效点（与导出逻辑一致）
    valid_lats = []
    valid_lons = []

    for t in range(n_times):
        for i in range(n_lats):
            for j in range(n_lons):
                # 检查该点是否为有效点（所有变量都不是NaN）
                is_valid = True
                for var in existing_vars:
                    val = ds[var].values[t, i, j]
                    if np.isnan(val):
                        is_valid = False
                        break

                if is_valid:
                    valid_lats.append(lats[i])
                    valid_lons.append(lons[j])

    valid_lats = np.array(valid_lats)
    valid_lons = np.array(valid_lons)

    print(f"  有效网格点数量: {len(valid_lats)}")

    # ============================================================================
    # 2. 读取PARSEC输出结果
    # ============================================================================
    print("\n读取PARSEC输出结果...")
    data_file = 'PARSEC_UKESM_EA_noMCB.dat'

    # 跳过第一行（列名），读取数据
    data = np.loadtxt(data_file, skiprows=1)
    print(f"  数据维度: {data.shape}")

    # 提取Nact（第20列，索引19）
    Nact = data[:, 15]  # 单位: m⁻³
    print(f"  Nact范围: {Nact.min() / 1e6:.0f} - {Nact.max() / 1e6:.0f} cm⁻³")

    # 检查数据点数是否匹配
    if len(Nact) != len(valid_lats):
        print(f"警告: 数据点数({len(Nact)})与有效网格点数({len(valid_lats)})不匹配")
        print("  可能原因: PARSEC输出时又删除了额外的行？")
        # 取较小的长度
        min_len = min(len(Nact), len(valid_lats))
        Nact = Nact[:min_len]
        valid_lats = valid_lats[:min_len]
        valid_lons = valid_lons[:min_len]
        print(f"  截取后: {len(Nact)} 点")

    # ============================================================================
    # 3. 重构为二维网格
    # ============================================================================
    print("\n重构为二维网格...")

    # 获取唯一的纬度和经度
    unique_lats = np.sort(np.unique(valid_lats))
    unique_lons = np.sort(np.unique(valid_lons))

    n_lats_unique = len(unique_lats)
    n_lons_unique = len(unique_lons)

    print(f"  唯一纬度: {n_lats_unique} 点 ({unique_lats[0]:.1f}° to {unique_lats[-1]:.1f}°)")
    print(f"  唯一经度: {n_lons_unique} 点 ({unique_lons[0]:.1f}° to {unique_lons[-1]:.1f}°)")
    print(f"  期望网格大小: {n_lats_unique} × {n_lons_unique} = {n_lats_unique * n_lons_unique}")
    print(f"  实际数据点数: {len(valid_lats)}")

    # 创建经纬度到索引的映射
    lat_to_idx = {lat: i for i, lat in enumerate(unique_lats)}
    lon_to_idx = {lon: j for j, lon in enumerate(unique_lons)}

    # 初始化二维数组
    Nact_2d = np.full((n_lats_unique, n_lons_unique), np.nan)

    # 填充数据
    for i in range(len(valid_lats)):
        lat_idx = lat_to_idx[valid_lats[i]]
        lon_idx = lon_to_idx[valid_lons[i]]
        Nact_2d[lat_idx, lon_idx] = Nact[i]

    # 转换为cm⁻³便于可视化
    Nact_2d_cm3 = Nact_2d / 1e6

    # 统计有效数据点
    valid_count = np.sum(~np.isnan(Nact_2d_cm3))
    print(
        f"  二维网格中有效数据点: {valid_count} / {n_lats_unique * n_lons_unique} ({100 * valid_count / (n_lats_unique * n_lons_unique):.1f}%)")

    # ============================================================================
    # 4. 绘制地图（使用与MCBSensitivityAnalysis相同的风格）
    # ============================================================================
    print("\n绘制地图...")

    # 创建图形
    fig = plt.figure(figsize=(14, 8))
    ax = plt.axes(projection=ccrs.PlateCarree())

    # 处理缺失值 - 使用 masked array
    data_plot = np.ma.masked_invalid(Nact_2d_cm3)

    # 检查是否有有效数据
    if data_plot.count() == 0:
        print("警告: 没有有效数据点，跳过绘图")
        return None

    # 获取经度纬度并确保正确排序
    lons_plot = unique_lons.copy()
    lats_plot = unique_lats.copy()

    # 确保经度在 -180 到 180 范围内
    if np.max(lons_plot) > 180:
        lons_plot = np.where(lons_plot > 180, lons_plot - 360, lons_plot)
        sort_idx = np.argsort(lons_plot)
        lons_plot = lons_plot[sort_idx]
        data_plot = data_plot[:, sort_idx]

    # 确保纬度从小到大排序
    if not np.all(np.diff(lats_plot) >= 0):
        sort_idx = np.argsort(lats_plot)
        lats_plot = lats_plot[sort_idx]
        data_plot = data_plot[sort_idx, :]

    # 设置颜色范数
    vmin = np.nanmin(Nact_2d_cm3)
    vmax = np.nanmax(Nact_2d_cm3)
    vcenter = np.nanmedian(Nact_2d_cm3)

    # 使用对称颜色范数（如果需要）
    # 对于Nact，通常不需要对称，使用viridis colormap
    # 但如果想用diverging colormap，可以设置center
    use_diverging = False  # 设为True可以使用RdBu风格

    if use_diverging and vcenter is not None:
        max_abs = max(abs(vmin - vcenter), abs(vmax - vcenter))
        sym_vmin = vcenter - max_abs
        sym_vmax = vcenter + max_abs
        norm = TwoSlopeNorm(vmin=sym_vmin, vcenter=vcenter, vmax=sym_vmax)
        cmap = 'RdBu_r'
    else:
        norm = None
        cmap = 'viridis'

    # 创建网格
    lon_grid, lat_grid = np.meshgrid(lons_plot, lats_plot)

    # 绘制地图（使用pcolormesh）
    im = ax.pcolormesh(lon_grid, lat_grid, data_plot,
                       cmap=cmap, norm=norm,
                       transform=ccrs.PlateCarree(),
                       shading='auto')

    # 添加地理特征
    ax.add_feature(cfeature.COASTLINE, linewidth=0.8)
    ax.add_feature(cfeature.BORDERS, linewidth=0.5, alpha=0.5)
    ax.add_feature(cfeature.OCEAN, alpha=0.1)

    # 添加网格线
    gl = ax.gridlines(draw_labels=True, dms=True,
                      x_inline=False, y_inline=False,
                      linewidth=0.5, alpha=0.5)
    gl.top_labels = False
    gl.right_labels = False

    # 设置地图范围（全球）
    ax.set_global()

    # 添加颜色条
    cbar = plt.colorbar(im, ax=ax, label='Nact (cm⁻³)', fraction=0.046, pad=0.04)
    cbar.ax.tick_params(labelsize=10)

    # 标题
    title = f'PARSEC Simulated Nact Distribution\n' \
            f'Range: {vmin:.0f} - {vmax:.0f} cm⁻³, ' \
            f'Mean: {np.nanmean(Nact_2d_cm3):.0f} cm⁻³, ' \
            f'Std: {np.nanstd(Nact_2d_cm3):.0f} cm⁻³'

    plt.title(title, fontsize=14, fontweight='bold')

    plt.tight_layout()

    # 保存图片
    output_file = 'PARSEC_UKESM_EA_noMCB_map.png'
    plt.savefig(output_file, dpi=200, bbox_inches='tight')
    plt.show()

    print(f"  地图已保存: {output_file}")

    # ============================================================================
    # 5. 额外：绘制纬度平均剖面图（与之前风格一致）
    # ============================================================================
    print("\n绘制纬度平均剖面图...")

    fig, ax = plt.subplots(figsize=(12, 6))

    # 计算纬度平均（经向平均）
    zonal_mean = np.nanmean(Nact_2d_cm3, axis=1)

    # 绘制
    ax.plot(lats_plot, zonal_mean, 'b-', linewidth=2, marker='o', markersize=4)
    ax.fill_between(lats_plot, zonal_mean, alpha=0.3, color='blue')

    ax.set_xlabel('Latitude (°)', fontsize=12)
    ax.set_ylabel('Nact (cm⁻³)', fontsize=12)
    ax.set_title('Zonal Mean Nact from PARSEC Simulation', fontsize=14, fontweight='bold')
    ax.grid(True, alpha=0.3)

    # 添加统计信息文本框
    stats_text = f'Mean: {np.nanmean(zonal_mean):.0f} cm⁻³\n' \
                 f'Max: {np.nanmax(zonal_mean):.0f} cm⁻³\n' \
                 f'Min: {np.nanmin(zonal_mean):.0f} cm⁻³'

    ax.text(0.02, 0.98, stats_text, transform=ax.transAxes,
            fontsize=10, verticalalignment='top',
            bbox=dict(boxstyle='round', facecolor='wheat', alpha=0.5))

    plt.tight_layout()

    # 保存纬度剖面图
    profile_file = 'PARSEC_UKESM_EA_noMCB_zonal_profile.png'
    plt.savefig(profile_file, dpi=150, bbox_inches='tight')
    plt.show()
    print(f"  纬度剖面图已保存: {profile_file}")

    # ============================================================================
    # 6. 统计信息
    # ============================================================================
    print("\n" + "=" * 60)
    print("统计信息")
    print("=" * 60)
    print(f"  Nact范围: {vmin:.0f} - {vmax:.0f} cm⁻³")
    print(f"  Nact平均值: {np.nanmean(Nact_2d_cm3):.0f} cm⁻³")
    print(f"  Nact标准差: {np.nanstd(Nact_2d_cm3):.0f} cm⁻³")
    print(f"  Nact中位数: {np.nanmedian(Nact_2d_cm3):.0f} cm⁻³")

    # 分纬度统计
    lat_bands = [(-90, -60), (-60, -30), (-30, 0), (0, 30), (30, 60), (60, 90)]
    print("\n纬度带平均Nact:")
    for lat_min, lat_max in lat_bands:
        mask = (lats_plot >= lat_min) & (lats_plot <= lat_max)
        if np.any(mask):
            band_data = Nact_2d_cm3[mask, :]
            mean_val = np.nanmean(band_data)
            if not np.isnan(mean_val):
                print(f"  {lat_min:3d}° to {lat_max:3d}°: {mean_val:.0f} cm⁻³")

    ds.close()

    return lats_plot, lons_plot, Nact_2d_cm3


def compare_baseline_mcb_maps():
    """
    比较PARSEC、DNN和UKESM1模型的Baseline和MCB预测结果
    绘制2行5列的对比图：第一行Baseline，第二行MCB
    每行：PARSEC结果 | DNN预测结果 | UKESM1结果 | UKESM1-PARSEC差值 | DNN-PARSEC差值
    注意：第二行（MCB）的第3、4列没有数据，第5列有数据
    """
    import numpy as np
    import xarray as xr
    import matplotlib.pyplot as plt
    import cartopy.crs as ccrs
    import cartopy.feature as cfeature
    from matplotlib.colors import TwoSlopeNorm

    # ============================================================================
    # 1. 设置参数和经纬度范围
    # ============================================================================
    lat_range = (0, 60)  # 0-60N
    lon_range = (60, 180)  # 60-180E

    # ============================================================================
    # 2. 读取PARSEC数据并重构为2D网格
    # ============================================================================
    def read_parsec_data(data_file, nc_file, lat_range, lon_range, nact_col):
        """读取PARSEC .dat文件并重构为2D网格
        nact_col: Nact所在的列索引 (noMCB:15, withMCB:19)
        """
        # 获取经纬度信息
        ds = xr.open_dataset(nc_file)
        lats = ds['latitude'].values
        lons = ds['longitude'].values

        # 确定有效网格点（与PARSEC输出顺序一致）
        variables = ['air_press', 'ddry_AS', 'ddry_CS', 'ddry_KS', 'n_AS', 'n_CS', 'n_KS', 'nact_cldrp_tot']
        existing_vars = [var for var in variables if var in ds.variables]

        # 构建有效点列表
        valid_lats, valid_lons = [], []
        for i in range(len(lats)):
            for j in range(len(lons)):
                is_valid = True
                for var in existing_vars:
                    if np.isnan(ds[var].values[0, i, j]):
                        is_valid = False
                        break
                if is_valid:
                    valid_lats.append(lats[i])
                    valid_lons.append(lons[j])

        valid_lats = np.array(valid_lats)
        valid_lons = np.array(valid_lons)

        # 读取PARSEC数据
        data = np.loadtxt(data_file, skiprows=1)
        Nact = data[:, nact_col]  # 根据文件选择正确的列

        # 截取匹配长度
        min_len = min(len(Nact), len(valid_lats))
        Nact = Nact[:min_len]
        valid_lats = valid_lats[:min_len]
        valid_lons = valid_lons[:min_len]

        # 过滤指定经纬度范围
        mask = (valid_lats >= lat_range[0]) & (valid_lats <= lat_range[1]) & \
               (valid_lons >= lon_range[0]) & (valid_lons <= lon_range[1])

        valid_lats = valid_lats[mask]
        valid_lons = valid_lons[mask]
        Nact = Nact[mask]

        # 重构2D网格
        unique_lats = np.sort(np.unique(valid_lats))
        unique_lons = np.sort(np.unique(valid_lons))

        Nact_2d = np.full((len(unique_lats), len(unique_lons)), np.nan)
        lat_to_idx = {lat: i for i, lat in enumerate(unique_lats)}
        lon_to_idx = {lon: j for j, lon in enumerate(unique_lons)}

        for i in range(len(valid_lats)):
            Nact_2d[lat_to_idx[valid_lats[i]], lon_to_idx[valid_lons[i]]] = Nact[i]

        ds.close()
        return unique_lats, unique_lons, Nact_2d / 1e6  # 转换为cm⁻³

    # ============================================================================
    # 3. 读取DNN模型预测数据
    # ============================================================================
    def read_dnn_predictions(npz_file, lat_range, lon_range):
        """读取DNN模型预测的npz文件"""
        data = np.load(npz_file)

        # 获取数据
        Nact_bg = data['Nact_bg'] / 1e6  # 转换为cm⁻³
        Nact_mcb = data['Nact_mcb'] / 1e6
        lats = data['lats']
        lons = data['lons']

        # 过滤指定经纬度范围
        lat_mask = (lats >= lat_range[0]) & (lats <= lat_range[1])
        lon_mask = (lons >= lon_range[0]) & (lons <= lon_range[1])

        lats_filtered = lats[lat_mask]
        lons_filtered = lons[lon_mask]
        Nact_bg_filtered = Nact_bg[lat_mask, :][:, lon_mask]
        Nact_mcb_filtered = Nact_mcb[lat_mask, :][:, lon_mask]

        return lats_filtered, lons_filtered, Nact_bg_filtered, Nact_mcb_filtered

    # ============================================================================
    # 4. 读取UKESM1数据
    # ============================================================================
    def read_ukesm1_data(nc_file, lat_range, lon_range):
        """读取UKESM1的nact_cldrp_tot数据"""
        ds = xr.open_dataset(nc_file)

        # 提取nact_cldrp_tot (time=0)
        Nact_ukesm1 = ds['nact_cldrp_tot'].values[0, :, :] / 1e6  # 转换为cm⁻³
        lats = ds['latitude'].values
        lons = ds['longitude'].values

        # 过滤指定经纬度范围
        lat_mask = (lats >= lat_range[0]) & (lats <= lat_range[1])
        lon_mask = (lons >= lon_range[0]) & (lons <= lon_range[1])

        lats_filtered = lats[lat_mask]
        lons_filtered = lons[lon_mask]
        Nact_filtered = Nact_ukesm1[lat_mask, :][:, lon_mask]

        ds.close()
        return lats_filtered, lons_filtered, Nact_filtered

    # ============================================================================
    # 5. 绘图函数
    # ============================================================================
    def plot_map(ax, data, lats, lons, title, cmap='viridis', norm=None):
        """绘制单个地图"""
        data_plot = np.ma.masked_invalid(data)
        if data_plot.count() == 0:
            ax.text(0.5, 0.5, 'No Data', transform=ax.transAxes, ha='center', va='center')
            ax.set_title(title, fontsize=8, fontweight='bold')
            return None

        # 处理经度范围
        if np.max(lons) > 180:
            lons_plot = np.where(lons > 180, lons - 360, lons)
            sort_idx = np.argsort(lons_plot)
            lons_plot = lons_plot[sort_idx]
            data_plot = data_plot[:, sort_idx]
        else:
            lons_plot = lons

        lon_grid, lat_grid = np.meshgrid(lons_plot, lats)

        im = ax.pcolormesh(lon_grid, lat_grid, data_plot, cmap=cmap, norm=norm,
                           transform=ccrs.PlateCarree(), shading='auto')

        ax.add_feature(cfeature.COASTLINE, linewidth=0.5)
        ax.add_feature(cfeature.BORDERS, linewidth=0.3, alpha=0.5)
        ax.set_extent([lons_plot.min(), lons_plot.max(), lats.min(), lats.max()], crs=ccrs.PlateCarree())

        # 添加统计信息到标题
        mean_val = np.nanmean(data_plot)
        std_val = np.nanstd(data_plot)
        ax.set_title(f'{title}\n(mean={mean_val:.0f}, std={std_val:.0f})',
                     fontsize=8, fontweight='bold')
        return im

    # ============================================================================
    # 6. 主程序：读取数据并绘图
    # ============================================================================
    print("=" * 60)
    print("比较PARSEC、DNN和UKESM1模型预测结果")
    print("=" * 60)

    # 读取PARSEC数据（注意列索引：noMCB是15，withMCB是19）
    print("\n读取PARSEC数据...")
    print("  noMCB文件: 第16列 (索引15)")
    lats_parsec_bg, lons_parsec_bg, Nact_bg_parsec = read_parsec_data(
        'PARSEC_UKESM_EA_noMCB.dat', '../outEA.nc', lat_range, lon_range, nact_col=15
    )

    print("  withMCB文件: 第20列 (索引19)")
    lats_parsec_mcb, lons_parsec_mcb, Nact_mcb_parsec = read_parsec_data(
        'PARSEC_UKESM_EA_withMCB.dat', '../outEA.nc', lat_range, lon_range, nact_col=19
    )

    # 读取DNN预测数据
    print("\n读取DNN预测数据...")
    lats_dnn, lons_dnn, Nact_bg_dnn, Nact_mcb_dnn = read_dnn_predictions(
        'baseline_mcb_data.npz', lat_range, lon_range
    )

    # 读取UKESM1数据
    print("\n读取UKESM1数据...")
    lats_ukesm1, lons_ukesm1, Nact_ukesm1 = read_ukesm1_data('../outEA.nc', lat_range, lon_range)

    # 检查网格是否一致
    print(f"\n网格信息:")
    print(f"  PARSEC Baseline: {Nact_bg_parsec.shape}")
    print(f"  PARSEC MCB:      {Nact_mcb_parsec.shape}")
    print(f"  DNN:             {Nact_bg_dnn.shape}")
    print(f"  UKESM1:          {Nact_ukesm1.shape}")

    # 计算差值
    # UKESM1 - PARSEC (Baseline)
    diff_ukesm1_parsec_bg = Nact_ukesm1 - Nact_bg_parsec
    # DNN - PARSEC (Baseline)
    diff_dnn_parsec_bg = Nact_bg_dnn - Nact_bg_parsec
    # DNN - PARSEC (MCB)
    diff_dnn_parsec_mcb = Nact_mcb_dnn - Nact_mcb_parsec

    # ============================================================================
    # 7. 绘制对比图 (2行5列)
    # ============================================================================
    print("\n绘制对比图...")

    # 创建图形，调整布局为colorbar留出空间
    fig = plt.figure(figsize=(22, 5))

    # 创建子图网格：2行5列，底部预留空间给colorbar
    gs = fig.add_gridspec(2, 5, hspace=0.05, wspace=0.05, bottom=0.12)

    axes = []
    for i in range(2):
        row = []
        for j in range(5):
            ax = fig.add_subplot(gs[i, j], projection=ccrs.PlateCarree())
            row.append(ax)
        axes.append(row)

    # 计算第1-3列的统一颜色范围（Nact值）
    all_data_rainbow = np.concatenate([
        Nact_bg_parsec[~np.isnan(Nact_bg_parsec)],
        Nact_bg_dnn[~np.isnan(Nact_bg_dnn)],
        Nact_ukesm1[~np.isnan(Nact_ukesm1)],
        Nact_mcb_parsec[~np.isnan(Nact_mcb_parsec)],
        Nact_mcb_dnn[~np.isnan(Nact_mcb_dnn)]
    ])
    vmin_rainbow = np.nanmin(all_data_rainbow)
    vmax_rainbow = np.nanmax(all_data_rainbow)
    norm_rainbow = plt.Normalize(vmin=vmin_rainbow, vmax=vmax_rainbow)

    # 计算差值列的统一颜色范围（对称于0）
    all_diff = np.concatenate([
        diff_ukesm1_parsec_bg[~np.isnan(diff_ukesm1_parsec_bg)],
        diff_dnn_parsec_bg[~np.isnan(diff_dnn_parsec_bg)],
        diff_dnn_parsec_mcb[~np.isnan(diff_dnn_parsec_mcb)]
    ])
    max_abs_diff = max(abs(np.nanmin(all_diff)), abs(np.nanmax(all_diff)))
    norm_diff = TwoSlopeNorm(vmin=-100, vcenter=0, vmax=100)

    # ========== 第一行：Baseline (Nact_bg) ==========
    # 第1列：PARSEC
    im1 = plot_map(axes[0][0], Nact_bg_parsec, lats_parsec_bg, lons_parsec_bg,
                   'PARSEC - noMCB', cmap='rainbow', norm=norm_rainbow)
    # 第2列：DNN预测
    im2 = plot_map(axes[0][1], Nact_bg_dnn, lats_dnn, lons_dnn,
                   'DNN - noMCB', cmap='rainbow', norm=norm_rainbow)
    # 第3列：UKESM1
    im3 = plot_map(axes[0][2], Nact_ukesm1, lats_ukesm1, lons_ukesm1,
                   'UKESM1 - noMCB', cmap='rainbow', norm=norm_rainbow)
    # 第4列：UKESM1 - PARSEC差值
    im4 = plot_map(axes[0][3], diff_ukesm1_parsec_bg, lats_parsec_bg, lons_parsec_bg,
                   'UKESM1 - PARSEC', cmap='RdBu_r', norm=norm_diff)
    # 第5列：DNN - PARSEC差值
    im5 = plot_map(axes[0][4], diff_dnn_parsec_bg, lats_dnn, lons_dnn,
                   'DNN - PARSEC', cmap='RdBu_r', norm=norm_diff)

    # ========== 第二行：MCB (Nact_mcb) ==========
    # 第1列：PARSEC
    im6 = plot_map(axes[1][0], Nact_mcb_parsec, lats_parsec_mcb, lons_parsec_mcb,
                   'PARSEC - MCB', cmap='rainbow', norm=norm_rainbow)
    # 第2列：DNN预测
    im7 = plot_map(axes[1][1], Nact_mcb_dnn, lats_dnn, lons_dnn,
                   'DNN - MCB', cmap='rainbow', norm=norm_rainbow)

    # 第3列：UKESM1（第二行无数据）
    axes[1][2].text(0.5, 0.5, 'No MCB Data\nin UKESM1', transform=axes[1][2].transAxes,
                    ha='center', va='center', fontsize=10, color='gray')
    axes[1][2].set_title('UKESM1 - MCB (No Data)', fontsize=8, fontweight='bold')
    axes[1][2].add_feature(cfeature.COASTLINE, linewidth=0.5)
    axes[1][2].add_feature(cfeature.BORDERS, linewidth=0.3, alpha=0.5)
    axes[1][2].set_extent([lons_ukesm1.min(), lons_ukesm1.max(),
                           lats_ukesm1.min(), lats_ukesm1.max()], crs=ccrs.PlateCarree())

    # 第4列：UKESM1 - PARSEC差值（第二行无数据）
    axes[1][3].text(0.5, 0.5, 'No MCB Data\nin UKESM1', transform=axes[1][3].transAxes,
                    ha='center', va='center', fontsize=10, color='gray')
    axes[1][3].set_title('UKESM1 - PARSEC (No Data)', fontsize=8, fontweight='bold')
    axes[1][3].add_feature(cfeature.COASTLINE, linewidth=0.5)
    axes[1][3].add_feature(cfeature.BORDERS, linewidth=0.3, alpha=0.5)
    axes[1][3].set_extent([lons_ukesm1.min(), lons_ukesm1.max(),
                           lats_ukesm1.min(), lats_ukesm1.max()], crs=ccrs.PlateCarree())

    # 第5列：DNN - PARSEC差值（第二行有数据）
    im8 = plot_map(axes[1][4], diff_dnn_parsec_mcb, lats_dnn, lons_dnn,
                   'DNN - PARSEC', cmap='RdBu_r', norm=norm_diff)

    # 添加横放的colorbar
    # 第1-3列的colorbar (rainbow)
    cbar_ax1 = fig.add_axes([0.15, 0.05, 0.35, 0.02])  # [left, bottom, width, height]
    cbar1 = fig.colorbar(im2, cax=cbar_ax1, orientation='horizontal', label='Nact (cm⁻³)')
    cbar1.ax.tick_params(labelsize=9)

    # 第4-5列的colorbar (RdBu_r)
    cbar_ax2 = fig.add_axes([0.62, 0.05, 0.25, 0.02])
    cbar2 = fig.colorbar(im5, cax=cbar_ax2, orientation='horizontal', label='Difference (cm⁻³)')
    cbar2.ax.tick_params(labelsize=9)

    # 添加总标题
    plt.suptitle('Comparison: PARSEC vs DNN vs UKESM1 @time0 (0-60°N, 60-180°E)',
                 fontsize=14, fontweight='bold', y=0.98)

    # 保存图片
    output_file = 'PARSEC_vs_DNN_vs_UKESM1_comparison.png'
    plt.savefig(output_file, dpi=200, bbox_inches='tight')
    plt.show()

    print(f"\n对比图已保存: {output_file}")

    # ============================================================================
    # 8. 打印统计信息
    # ============================================================================
    print("\n" + "=" * 60)
    print("统计信息 (0-60°N, 60-180°E)")
    print("=" * 60)

    print(f"\nBaseline Nact (cm⁻³):")
    print(f"  PARSEC: Mean={np.nanmean(Nact_bg_parsec):.0f}, Std={np.nanstd(Nact_bg_parsec):.0f}")
    print(f"  DNN:    Mean={np.nanmean(Nact_bg_dnn):.0f}, Std={np.nanstd(Nact_bg_dnn):.0f}")
    print(f"  UKESM1: Mean={np.nanmean(Nact_ukesm1):.0f}, Std={np.nanstd(Nact_ukesm1):.0f}")
    print(f"  UKESM1-PARSEC: Mean={np.nanmean(diff_ukesm1_parsec_bg):.0f}, Std={np.nanstd(diff_ukesm1_parsec_bg):.0f}")
    print(f"  DNN-PARSEC:    Mean={np.nanmean(diff_dnn_parsec_bg):.0f}, Std={np.nanstd(diff_dnn_parsec_bg):.0f}")

    print(f"\nMCB Nact (cm⁻³):")
    print(f"  PARSEC: Mean={np.nanmean(Nact_mcb_parsec):.0f}, Std={np.nanstd(Nact_mcb_parsec):.0f}")
    print(f"  DNN:    Mean={np.nanmean(Nact_mcb_dnn):.0f}, Std={np.nanstd(Nact_mcb_dnn):.0f}")
    print(f"  DNN-PARSEC:    Mean={np.nanmean(diff_dnn_parsec_mcb):.0f}, Std={np.nanstd(diff_dnn_parsec_mcb):.0f}")

    # 额外：计算增强效果
    print(f"\n增强效果 (MCB - Baseline):")
    print(f"  PARSEC: Mean={np.nanmean(Nact_mcb_parsec - Nact_bg_parsec):.0f} cm⁻³")
    print(f"  DNN:    Mean={np.nanmean(Nact_mcb_dnn - Nact_bg_dnn):.0f} cm⁻³")






